SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-power", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A battery of EMF 12 V and internal resistance 2 Ω is connected to a 4 Ω resistor. The power dissipated in the internal resistance is:", "explanation": "Total resistance = R + r = 4 + 2 = 6 Ω. Current I = EMF/(R+r) = 12/6 = 2 A. Power dissipated in internal resistance = I²r = (2)² × 2 = 8 W.", "correct_answer": "C", "concept_tags": ["internal-resistance", "power-dissipation", "P=I²R"], "payload": {"question_id": "cuet-phy-current-power-17", "subtopic": "P=I²R", "topic_name": "Electrical Energy and Power", "bloom_level": "apply", "options": [{"key": "A", "text": "24 W", "is_correct": false}, {"key": "B", "text": "16 W", "is_correct": false}, {"key": "C", "text": "8 W", "is_correct": true}, {"key": "D", "text": "4 W", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "24 W = EMF × I = 12 × 2 — this is the total power delivered by the battery, not just the internal dissipation.", "misconception": "Confusing total power with power in internal resistance"}, {"option_key": "B", "hint": "16 W = I² × R = 4 × 4 — this is the power dissipated in the external resistor.", "misconception": "Calculating power in the external resistor instead of internal resistance"}, {"option_key": "D", "hint": "4 W would imply I = √(P/r) = √2 A, which is incorrect.", "misconception": "Arithmetic error in current or power calculation"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-power", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two heaters rated 200 W, 220 V and 100 W, 220 V are connected in parallel to a 220 V supply. The total power consumed is:", "explanation": "In parallel across rated voltage, each heater operates at its rated power. Total power = 200 + 100 = 300 W. In parallel, powers simply add up when the supply voltage equals the rated voltage.", "correct_answer": "A", "concept_tags": ["power-in-parallel", "rated-power", "heaters"], "payload": {"question_id": "cuet-phy-current-power-18", "subtopic": "power in series/parallel circuits", "topic_name": "Electrical Energy and Power", "bloom_level": "apply", "options": [{"key": "A", "text": "300 W", "is_correct": true}, {"key": "B", "text": "150 W", "is_correct": false}, {"key": "C", "text": "100 W", "is_correct": false}, {"key": "D", "text": "400 W", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "150 W would be the average, but powers in parallel add, not average.", "misconception": "Averaging power ratings instead of adding them"}, {"option_key": "C", "hint": "100 W is only the rating of one heater, not the total.", "misconception": "Selecting only one component''s power as total"}, {"option_key": "D", "hint": "400 W = 2 × 200 — this doubles one rating instead of adding both.", "misconception": "Incorrect arithmetic in power addition"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-power", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An immersion heater rated 1 kW, 220 V is used to heat 1 kg of water from 20°C to 100°C. Assuming no heat loss and specific heat of water = 4200 J/(kg·°C), the time required is approximately:", "explanation": "Heat required Q = mcΔT = 1 × 4200 × (100 - 20) = 1 × 4200 × 80 = 336,000 J. Time t = Q/P = 336,000/1000 = 336 s ≈ 5.6 minutes ≈ 336 s.", "correct_answer": "B", "concept_tags": ["joule-heating", "specific-heat", "immersion-heater", "E=Pt"], "payload": {"question_id": "cuet-phy-current-power-19", "subtopic": "electric heater/iron/bulb", "topic_name": "Electrical Energy and Power", "bloom_level": "apply", "options": [{"key": "A", "text": "168 s", "is_correct": false}, {"key": "B", "text": "336 s", "is_correct": true}, {"key": "C", "text": "672 s", "is_correct": false}, {"key": "D", "text": "420 s", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "168 s = 336/2, likely from halving the temperature difference or using wrong specific heat.", "misconception": "Using ΔT = 40°C instead of 80°C"}, {"option_key": "C", "hint": "672 s = 2 × 336, possibly from using 2 kg or doubling somewhere incorrectly.", "misconception": "Doubling the mass or temperature difference"}, {"option_key": "D", "hint": "420 s = 4200 × 100/1000, likely from using T = 100°C instead of ΔT = 80°C.", "misconception": "Using final temperature instead of temperature change"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-power", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A 100 W, 200 V bulb is connected to a 160 V supply. The actual power consumed by the bulb is:", "explanation": "Resistance of bulb R = V_rated²/P_rated = (200)²/100 = 400 Ω. At 160 V supply, actual power P = V²/R = (160)²/400 = 25600/400 = 64 W.", "correct_answer": "D", "concept_tags": ["power-rating", "actual-power", "P=V²/R"], "payload": {"question_id": "cuet-phy-current-power-20", "subtopic": "power rating of appliances", "topic_name": "Electrical Energy and Power", "bloom_level": "analyze", "options": [{"key": "A", "text": "100 W", "is_correct": false}, {"key": "B", "text": "80 W", "is_correct": false}, {"key": "C", "text": "125 W", "is_correct": false}, {"key": "D", "text": "64 W", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "100 W is the rated power at 200 V. At a lower voltage, the bulb consumes less power.", "misconception": "Assuming rated power is always consumed regardless of supply voltage"}, {"option_key": "B", "hint": "80 W = 100 × (160/200), assuming linear proportionality, but P ∝ V², not V.", "misconception": "Assuming power is linearly proportional to voltage"}, {"option_key": "C", "hint": "125 W > 100 W; power cannot exceed rated power at a lower voltage.", "misconception": "Inverting the voltage ratio"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-power", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The power dissipated in a resistor is P = I²R when a constant current passes through it.\nReason (R): By Ohm''s law, V = IR, and substituting in P = VI gives P = I²R.", "explanation": "Both the assertion and the reason are true. The assertion states the correct formula for power dissipation with constant current. The reason correctly derives this formula by combining P = VI with Ohm''s law V = IR, giving P = (IR)I = I²R. Hence R is the correct explanation of A.", "correct_answer": "A", "concept_tags": ["P=I²R", "ohms-law", "power-derivation"], "payload": {"question_id": "cuet-phy-current-power-25", "subtopic": "P=I²R", "topic_name": "Electrical Energy and Power", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are true, and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason directly derives the formula stated in the assertion, so it is the correct explanation.", "misconception": "Failing to see the logical connection between derivation and result"}, {"option_key": "C", "hint": "The reason correctly applies Ohm''s law substitution — V = IR is valid for ohmic conductors.", "misconception": "Doubting the validity of Ohm''s law substitution"}, {"option_key": "D", "hint": "P = I²R is a well-established formula for power dissipation; the assertion is true.", "misconception": "Rejecting a correct formula"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-power", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): In a parallel combination, the appliance with the lowest resistance consumes the maximum power.\nReason (R): In a parallel combination, the voltage across each appliance is the same, and P = V²/R.", "explanation": "Both A and R are true. In parallel, each device has the same voltage V across it. Using P = V²/R, the device with the smallest R will have the largest P. The reason directly explains why the assertion is true.", "correct_answer": "A", "concept_tags": ["power-in-parallel", "P=V²/R", "minimum-resistance"], "payload": {"question_id": "cuet-phy-current-power-26", "subtopic": "power in series/parallel circuits", "topic_name": "Electrical Energy and Power", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are true, and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R explains exactly why lower resistance means higher power in parallel (P = V²/R with same V), so it is the correct explanation.", "misconception": "Not recognizing the causal link between constant V and P ∝ 1/R"}, {"option_key": "C", "hint": "The reason correctly states that voltage is equal in parallel and applies P = V²/R.", "misconception": "Doubting that voltage is the same across parallel components"}, {"option_key": "D", "hint": "The assertion is correct — lower resistance does consume more power in parallel.", "misconception": "Thinking higher resistance consumes more power in parallel"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-power", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): When the external resistance in a circuit equals the internal resistance of the battery, the efficiency of the battery is 50%.\nReason (R): Maximum power is transferred to the external load when external resistance equals internal resistance.", "explanation": "Both A and R are true. When R = r, total power = ε²/(2r) and power in external load = ε²/(4r). Efficiency = P_external/P_total = [ε²/(4r)]/[ε²/(2r)] = 1/2 = 50%. The reason is true but does not explain efficiency — it explains maximum power transfer, which is a different concept. Efficiency at maximum power transfer happens to be 50%, but R talks about power, not efficiency.", "correct_answer": "B", "concept_tags": ["maximum-power-transfer", "battery-efficiency", "internal-resistance"], "payload": {"question_id": "cuet-phy-current-power-27", "subtopic": "maximum power transfer theorem", "topic_name": "Electrical Energy and Power", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are true, and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": true}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "While both are true, the reason discusses maximum power transfer, not efficiency. These are related but distinct concepts.", "misconception": "Equating maximum power transfer with efficiency explanation"}, {"option_key": "C", "hint": "The reason is true — the maximum power transfer theorem is a valid statement.", "misconception": "Rejecting the maximum power transfer theorem"}, {"option_key": "D", "hint": "The assertion is true — at R = r, efficiency is indeed 50%.", "misconception": "Incorrectly calculating battery efficiency"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-power", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): An electric bulb becomes dim when an electric heater connected in parallel with it is switched on.\nReason (R): The heater draws a large current, causing increased voltage drop across the lead wires, reducing voltage available to the bulb.", "explanation": "Both A and R are true, and R is the correct explanation of A. The heater has low resistance and draws a large current. This increases the total current through the household lead wires, causing a larger voltage drop (IR drop) across them. Consequently, the terminal voltage available at the appliance end decreases, making the bulb dimmer.", "correct_answer": "A", "concept_tags": ["voltage-drop", "lead-wires", "parallel-circuit", "practical-circuits"], "payload": {"question_id": "cuet-phy-current-power-28", "subtopic": "household wiring (why parallel not series)", "topic_name": "Electrical Energy and Power", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are true, and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason precisely explains the mechanism (IR drop in lead wires) that causes the dimming described in the assertion.", "misconception": "Not connecting voltage drop in lead wires to reduced brightness"}, {"option_key": "C", "hint": "The reason is true — increased current does cause more voltage drop in lead wires.", "misconception": "Ignoring resistance of connecting wires"}, {"option_key": "D", "hint": "The assertion is true — this is a commonly observed phenomenon in household circuits.", "misconception": "Denying a real-world observation"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-power", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I: (P) P = VI, (Q) P = I²R, (R) P = V²/R, (S) H = I²Rt\n\nColumn II: (1) Power when current is known but not voltage, (2) Electrical energy converted to heat, (3) Power when voltage is known but not current, (4) General formula for electrical power", "explanation": "P = VI is the general power formula (P-4). P = I²R is used when current and resistance are known (Q-1). P = V²/R is used when voltage and resistance are known (R-3). H = I²Rt gives total heat energy (Joule heating) over time t (S-2).", "correct_answer": "C", "concept_tags": ["power-formulas", "joule-heating", "formula-identification"], "payload": {"question_id": "cuet-phy-current-power-29", "subtopic": "P=VI", "topic_name": "Electrical Energy and Power", "bloom_level": "understand", "options": [{"key": "A", "text": "P-1, Q-2, R-3, S-4", "is_correct": false}, {"key": "B", "text": "P-3, Q-1, R-4, S-2", "is_correct": false}, {"key": "C", "text": "P-4, Q-1, R-3, S-2", "is_correct": true}, {"key": "D", "text": "P-4, Q-3, R-1, S-2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "P = VI is the general formula (match 4), not specific to current-known situations (1).", "misconception": "Not recognizing P = VI as the most general power formula"}, {"option_key": "B", "hint": "P = VI (match P) is the general formula (4), not the voltage-known formula (3).", "misconception": "Confusing the general formula with a specific case"}, {"option_key": "D", "hint": "Q = I²R relates to known current (1), and R = V²/R relates to known voltage (3), not the reverse.", "misconception": "Swapping the current-known and voltage-known formulas"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-power", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the electrical device/concept in Column I with its correct description in Column II:\n\nColumn I: (P) Fuse, (Q) Nichrome wire, (R) kWh meter, (S) MCB (Miniature Circuit Breaker)\n\nColumn II: (1) Measures electrical energy consumed, (2) Melts to break circuit on overloading, (3) Used as heating element due to high resistivity and high melting point, (4) Trips electromagnetically on excess current without needing replacement", "explanation": "Fuse melts and breaks the circuit (P-2). Nichrome has high resistivity and high melting point, ideal for heaters (Q-3). The kWh meter measures units of energy consumed (R-1). MCB uses electromagnetic tripping and can be reset, unlike fuses (S-4).", "correct_answer": "D", "concept_tags": ["fuse", "nichrome", "kWh-meter", "MCB", "electrical-devices"], "payload": {"question_id": "cuet-phy-current-power-30", "subtopic": "fuse rating", "topic_name": "Electrical Energy and Power", "bloom_level": "understand", "options": [{"key": "A", "text": "P-1, Q-3, R-2, S-4", "is_correct": false}, {"key": "B", "text": "P-4, Q-3, R-1, S-2", "is_correct": false}, {"key": "C", "text": "P-2, Q-4, R-1, S-3", "is_correct": false}, {"key": "D", "text": "P-2, Q-3, R-1, S-4", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Fuse melts (2), it does not measure energy (1). The kWh meter measures energy.", "misconception": "Confusing the fuse with the energy meter"}, {"option_key": "B", "hint": "Fuse melts and must be replaced (2), not trips and resets (4). MCB trips and resets.", "misconception": "Confusing fuse with MCB"}, {"option_key": "C", "hint": "Nichrome is a heating element (3), not a circuit breaker (4). MCB is the circuit breaker.", "misconception": "Confusing nichrome wire with MCB function"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-power", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "True or False: The commercial unit of electrical energy is the kilowatt-hour (kWh).", "explanation": "True. The kilowatt-hour is the standard commercial unit of electrical energy used for billing purposes. 1 kWh = 3.6 × 10⁶ J. It represents the energy consumed by a 1 kW appliance running for 1 hour.", "correct_answer": "A", "concept_tags": ["kilowatt-hour", "commercial-unit", "electrical-energy"], "payload": {"question_id": "cuet-phy-current-power-31", "subtopic": "kilowatt-hour", "topic_name": "Electrical Energy and Power", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The statement is correct. kWh is indeed the commercial unit of electrical energy, distinct from the SI unit (joule).", "misconception": "Confusing SI unit with commercial unit"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-power", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "True or False: In a series circuit, the total power consumed equals the sum of the rated powers of all individual appliances.", "explanation": "False. In a series circuit, the voltage is divided among the appliances, so each does not operate at its rated voltage. The actual power consumed by each appliance differs from its rated power. The total power equals V²/(R₁+R₂+...), not the sum of individual rated powers.", "correct_answer": "B", "concept_tags": ["power-in-series", "rated-power", "voltage-division"], "payload": {"question_id": "cuet-phy-current-power-32", "subtopic": "power in series/parallel circuits", "topic_name": "Electrical Energy and Power", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Rated power applies only at rated voltage. In series, voltage is divided, so each appliance gets less than rated voltage.", "misconception": "Assuming rated power is always consumed regardless of circuit configuration"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-power", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "medium", "question_text": "True or False: Overloading of a circuit occurs when too many appliances are connected to the same circuit, drawing current beyond the safe limit.", "explanation": "True. When many appliances are connected in parallel, the total current drawn increases (since I_total = I₁ + I₂ + ... in parallel). If this total current exceeds the rated capacity of the wiring, the circuit is overloaded, which can cause overheating and fire.", "correct_answer": "A", "concept_tags": ["overloading", "electrical-safety", "parallel-circuit"], "payload": {"question_id": "cuet-phy-current-power-33", "subtopic": "short circuit and overloading", "topic_name": "Electrical Energy and Power", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is the standard definition of overloading. More parallel appliances draw more total current.", "misconception": "Confusing overloading with short circuit"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-power", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "medium", "question_text": "True or False: The total power consumed by resistors in a series circuit is always greater than the power consumed by each individual resistor connected alone to the same voltage source.", "explanation": "False. In a series circuit, the total resistance increases, reducing the current. Each resistor receives only a fraction of the total voltage. The power consumed by each resistor in series (I²R with reduced I) is less than when it is connected alone across the full voltage (V²/R). Thus the total series power V²/(R₁+R₂+...) is actually less than any single resistor alone would consume at the full voltage.", "correct_answer": "B", "concept_tags": ["power-in-series", "power-in-parallel", "brightness"], "payload": {"question_id": "cuet-phy-current-power-34", "subtopic": "power in series/parallel circuits", "topic_name": "Electrical Energy and Power", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Consider the effect of internal resistance of the battery. With internal resistance, the analysis changes.", "misconception": "Ignoring internal resistance effects in real circuits"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-power", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "easy", "question_text": "The power consumed by an electrical appliance is given by the product of voltage and ______.", "explanation": "Power P = V × I (voltage × current). This is the fundamental formula for electrical power, where V is the potential difference across the device and I is the current flowing through it.", "correct_answer": "C", "concept_tags": ["P=VI", "electrical-power", "basic-formula"], "payload": {"question_id": "cuet-phy-current-power-35", "subtopic": "P=VI", "topic_name": "Electrical Energy and Power", "bloom_level": "remember", "options": [{"key": "A", "text": "Resistance", "is_correct": false}, {"key": "B", "text": "Energy", "is_correct": false}, {"key": "C", "text": "Current", "is_correct": true}, {"key": "D", "text": "Time", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "V × R does not give power. Power = VI or V²/R or I²R.", "misconception": "Confusing P = VI with P = VR"}, {"option_key": "B", "hint": "Energy = Power × Time, not the other way around.", "misconception": "Confusing energy with the components of power formula"}, {"option_key": "D", "hint": "V × t gives neither power nor energy directly. Energy = VIt, but power = VI.", "misconception": "Including time in the power formula"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-power", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "A 500 W heater is used for 4 hours daily. The electrical energy consumed in one day is ______ kWh.", "explanation": "Energy = Power × Time = 500 W × 4 h = 2000 Wh = 2 kWh. Converting watts to kilowatts: 500 W = 0.5 kW, so E = 0.5 × 4 = 2 kWh.", "correct_answer": "B", "concept_tags": ["electrical-energy", "E=Pt", "kilowatt-hour"], "payload": {"question_id": "cuet-phy-current-power-36", "subtopic": "electrical energy E=Pt", "topic_name": "Electrical Energy and Power", "bloom_level": "apply", "options": [{"key": "A", "text": "0.5", "is_correct": false}, {"key": "B", "text": "2", "is_correct": true}, {"key": "C", "text": "4", "is_correct": false}, {"key": "D", "text": "2000", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "0.5 kWh = 0.5 kW × 1 h, but the heater is used for 4 hours.", "misconception": "Using only 1 hour instead of 4 hours"}, {"option_key": "C", "hint": "4 kWh would require 1 kW power for 4 hours, but the heater is 500 W = 0.5 kW.", "misconception": "Not converting watts to kilowatts"}, {"option_key": "D", "hint": "2000 is in watt-hours, not kilowatt-hours. Divide by 1000 to convert.", "misconception": "Forgetting to convert Wh to kWh"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-power", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "What is the power dissipated in the external circuit (the parallel combination)?", "explanation": "The parallel combination: R_ext = (3 × 6)/(3 + 6) = 18/9 = 2 Ω. Total resistance = R_ext + r = 2 + 1 = 3 Ω. Current I = 12/3 = 4 A. Power in external circuit P_ext = I² × R_ext = 16 × 2 = 32 W. Alternatively, V_ext = IR_ext = 4 × 2 = 8 V, P_ext = V_ext²/R_ext = 64/2 = 32 W.", "correct_answer": "D", "concept_tags": ["parallel-resistance", "internal-resistance", "power-in-external-circuit"], "payload": {"question_id": "cuet-phy-current-power-37", "subtopic": "P=I²R", "topic_name": "Electrical Energy and Power", "bloom_level": "apply", "options": [{"key": "A", "text": "48 W", "is_correct": false}, {"key": "B", "text": "16 W", "is_correct": false}, {"key": "C", "text": "24 W", "is_correct": false}, {"key": "D", "text": "32 W", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "48 W = EMF × I = 12 × 4, which is the total power delivered by the battery, including internal dissipation.", "misconception": "Not subtracting internal resistance power loss"}, {"option_key": "B", "hint": "16 W = I² × r = 16 × 1, which is the power lost in the internal resistance.", "misconception": "Calculating power in internal resistance instead of external"}, {"option_key": "C", "hint": "24 W does not correspond to the correct calculation with these values.", "misconception": "Arithmetic error in equivalent resistance or current"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-power", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "What is the power lost in the connecting cables and the efficiency of power delivery to the appliances?", "explanation": "Total load power = 240 + 4 × 15 = 240 + 60 = 300 W. Total current drawn I = P_total/V = 300/48 = 6.25 A. Power loss in cables = I²R_cable = (6.25)² × 0.5 = 39.0625 × 0.5 ≈ 19.5 W. Total power from source = 300 + 19.5 = 319.5 W. Efficiency = 300/319.5 × 100 ≈ 93.9%. Closest answer: cable loss ≈ 19.5 W, efficiency ≈ 93.9%.", "correct_answer": "C", "concept_tags": ["power-loss", "cable-resistance", "efficiency", "practical-circuits"], "payload": {"question_id": "cuet-phy-current-power-38", "subtopic": "efficiency of electrical devices", "topic_name": "Electrical Energy and Power", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Cable loss ≈ 39 W, efficiency ≈ 88.5%", "is_correct": false}, {"key": "B", "text": "Cable loss ≈ 3.1 W, efficiency ≈ 99%", "is_correct": false}, {"key": "C", "text": "Cable loss ≈ 19.5 W, efficiency ≈ 93.9%", "is_correct": true}, {"key": "D", "text": "Cable loss ≈ 9.8 W, efficiency ≈ 96.8%", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "39 W uses R = 1 Ω instead of 0.5 Ω, or squares the current incorrectly.", "misconception": "Doubling the cable resistance or miscalculating I²R"}, {"option_key": "B", "hint": "3.1 W = IR = 6.25 × 0.5 — this uses IR instead of I²R for power loss.", "misconception": "Using P = IR instead of P = I²R"}, {"option_key": "D", "hint": "9.8 W ≈ I²R/2 — possible error of halving the correct power loss.", "misconception": "Dividing the power loss by 2 without justification"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-power", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following steps in the correct logical sequence for calculating the total electrical energy consumed by an appliance:\n\n(i) Convert power to kilowatts\n(ii) Note the power rating of the appliance in watts\n(iii) Multiply power (in kW) by time (in hours) to get energy in kWh\n(iv) Note the duration of usage in hours", "explanation": "The logical sequence is: first note the power rating in watts (ii), then convert to kilowatts (i), then note the duration of usage (iv), and finally multiply to get energy in kWh (iii). This gives E = P(kW) × t(h) in kWh.", "correct_answer": "B", "concept_tags": ["electrical-energy", "E=Pt", "kilowatt-hour", "unit-conversion"], "payload": {"question_id": "cuet-phy-current-power-39", "subtopic": "electrical energy E=Pt", "topic_name": "Electrical Energy and Power", "bloom_level": "apply", "options": [{"key": "A", "text": "(i) → (ii) → (iv) → (iii)", "is_correct": false}, {"key": "B", "text": "(ii) → (i) → (iv) → (iii)", "is_correct": true}, {"key": "C", "text": "(iv) → (ii) → (iii) → (i)", "is_correct": false}, {"key": "D", "text": "(ii) → (iv) → (i) → (iii)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "You must first note the power rating (ii) before you can convert it to kilowatts (i).", "misconception": "Converting to kW before knowing the watt rating"}, {"option_key": "C", "hint": "Multiplying (iii) must be the last step, after both power and time are known.", "misconception": "Performing calculation before having all required values"}, {"option_key": "D", "hint": "While close, it is more logical to convert watts to kilowatts (i) immediately after noting the watt rating (ii), before noting the time.", "misconception": "Delaying unit conversion to after noting time"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-power", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "hard", "question_text": "Arrange the following events in the correct sequence that occurs during a short circuit in a household electrical system:\n\n(i) Fuse wire melts and breaks the circuit\n(ii) Live wire accidentally touches neutral wire\n(iii) Circuit resistance drops to nearly zero\n(iv) Extremely large current flows through the circuit\n(v) Excessive Joule heating occurs in the fuse wire", "explanation": "The correct sequence: First, the live wire touches neutral (ii), causing resistance to drop to nearly zero (iii). This results in extremely large current (iv) as I = V/R with R → 0. The large current causes excessive Joule heating H = I²Rt in the fuse wire (v), which then melts and breaks the circuit (i), protecting the wiring.", "correct_answer": "D", "concept_tags": ["short-circuit", "fuse", "joule-heating", "electrical-safety", "overloading"], "payload": {"question_id": "cuet-phy-current-power-40", "subtopic": "short circuit and overloading", "topic_name": "Electrical Energy and Power", "bloom_level": "analyze", "options": [{"key": "A", "text": "(ii) → (iv) → (iii) → (v) → (i)", "is_correct": false}, {"key": "B", "text": "(iii) → (ii) → (iv) → (i) → (v)", "is_correct": false}, {"key": "C", "text": "(ii) → (iii) → (v) → (iv) → (i)", "is_correct": false}, {"key": "D", "text": "(ii) → (iii) → (iv) → (v) → (i)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Large current (iv) cannot flow before resistance drops (iii). The resistance drop causes the large current.", "misconception": "Placing effect before cause — current surge before resistance change"}, {"option_key": "B", "hint": "Resistance drops (iii) as a result of wire contact (ii), not before it.", "misconception": "Placing effect before cause — resistance drops before contact"}, {"option_key": "C", "hint": "Joule heating (v) results from large current (iv), not before it. The sequence of cause and effect is violated.", "misconception": "Placing heating before the current surge"}]}}]'::jsonb, 'deploy-2026-03-05-b03');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "multiple-choice", "difficulty": "easy", "question_text": "A galvanometer is converted into an ammeter by connecting a:", "explanation": "An ammeter must have very low resistance so it does not alter the current in the circuit. A low resistance (shunt) connected in parallel with the galvanometer bypasses most of the current, protecting the galvanometer while allowing measurement of large currents.", "correct_answer": "B", "concept_tags": ["ammeter-conversion", "shunt-resistance"], "payload": {"question_id": "cuet-phy-current-instruments-01", "subtopic": "ammeter conversion (shunt resistance)", "topic_name": "Measuring Instruments", "bloom_level": "Remember", "options": [{"key": "A", "text": "High resistance in series", "is_correct": false}, {"key": "B", "text": "Low resistance in parallel (shunt)", "is_correct": true}, {"key": "C", "text": "High resistance in parallel", "is_correct": false}, {"key": "D", "text": "Low resistance in series", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "High resistance in series is used for voltmeter conversion, not ammeter.", "misconception": "Confusing ammeter and voltmeter conversion methods"}, {"option_key": "C", "hint": "High resistance in parallel would not bypass sufficient current.", "misconception": "Misunderstanding the purpose of shunt resistance"}, {"option_key": "D", "hint": "Low resistance in series would still leave the galvanometer in the main path without protection.", "misconception": "Confusing series and parallel arrangements"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "multiple-choice", "difficulty": "easy", "question_text": "An ideal voltmeter has:", "explanation": "An ideal voltmeter should draw no current from the circuit so that it does not disturb the potential difference it is measuring. This requires infinite resistance.", "correct_answer": "C", "concept_tags": ["ideal-voltmeter", "infinite-resistance"], "payload": {"question_id": "cuet-phy-current-instruments-02", "subtopic": "ideal vs practical meters", "topic_name": "Measuring Instruments", "bloom_level": "Remember", "options": [{"key": "A", "text": "Zero resistance", "is_correct": false}, {"key": "B", "text": "Low resistance", "is_correct": false}, {"key": "C", "text": "Infinite resistance", "is_correct": true}, {"key": "D", "text": "Resistance equal to the circuit resistance", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Zero resistance describes an ideal ammeter, not a voltmeter.", "misconception": "Confusing ammeter and voltmeter ideal properties"}, {"option_key": "B", "hint": "Low resistance would cause the voltmeter to draw significant current, disturbing the circuit.", "misconception": "Not understanding why voltmeters need high resistance"}, {"option_key": "D", "hint": "Matching circuit resistance would still draw appreciable current.", "misconception": "Applying impedance matching concept incorrectly"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "multiple-choice", "difficulty": "easy", "question_text": "The resistance of an ideal ammeter is:", "explanation": "An ideal ammeter should not introduce any additional resistance in the circuit, so its resistance must be zero. This ensures the current being measured remains unchanged.", "correct_answer": "A", "concept_tags": ["ideal-ammeter", "zero-resistance"], "payload": {"question_id": "cuet-phy-current-instruments-03", "subtopic": "ideal vs practical meters", "topic_name": "Measuring Instruments", "bloom_level": "Remember", "options": [{"key": "A", "text": "Zero", "is_correct": true}, {"key": "B", "text": "Infinity", "is_correct": false}, {"key": "C", "text": "Very high", "is_correct": false}, {"key": "D", "text": "Equal to the external resistance", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Infinite resistance describes an ideal voltmeter.", "misconception": "Confusing ammeter and voltmeter properties"}, {"option_key": "C", "hint": "High resistance in an ammeter would reduce the circuit current significantly.", "misconception": "Not understanding ammeter placement in series"}, {"option_key": "D", "hint": "Matching external resistance would halve the current.", "misconception": "Applying maximum power transfer theorem inappropriately"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "multiple-choice", "difficulty": "easy", "question_text": "The sensitivity of a moving coil galvanometer can be increased by:", "explanation": "Current sensitivity = NAB/k. Increasing B (magnetic field strength) increases the deflection per unit current, thus increasing sensitivity. Increasing restoring torque (k) or decreasing N or A would decrease sensitivity.", "correct_answer": "D", "concept_tags": ["galvanometer-sensitivity", "magnetic-field"], "payload": {"question_id": "cuet-phy-current-instruments-04", "subtopic": "sensitivity of galvanometer", "topic_name": "Measuring Instruments", "bloom_level": "Understand", "options": [{"key": "A", "text": "Increasing the restoring torque per unit twist", "is_correct": false}, {"key": "B", "text": "Decreasing the number of turns of the coil", "is_correct": false}, {"key": "C", "text": "Decreasing the area of the coil", "is_correct": false}, {"key": "D", "text": "Using a stronger magnetic field", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Increasing restoring torque k decreases sensitivity since sensitivity = NAB/k.", "misconception": "Confusing direct and inverse proportionality"}, {"option_key": "B", "hint": "Decreasing N reduces the deflecting torque and thus sensitivity.", "misconception": "Not knowing the sensitivity formula"}, {"option_key": "C", "hint": "Decreasing area A reduces the torque on the coil.", "misconception": "Thinking smaller coils are more sensitive"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "multiple-choice", "difficulty": "medium", "question_text": "A galvanometer of resistance 50 Ω gives full-scale deflection for a current of 5 mA. To convert it into an ammeter of range 5 A, the shunt resistance required is:", "explanation": "Shunt resistance S = Ig × G / (I - Ig) = (5 × 10⁻³ × 50) / (5 - 0.005) = 0.25 / 4.995 ≈ 0.05 Ω.", "correct_answer": "A", "concept_tags": ["shunt-resistance", "ammeter-conversion", "numerical"], "payload": {"question_id": "cuet-phy-current-instruments-05", "subtopic": "ammeter conversion (shunt resistance)", "topic_name": "Measuring Instruments", "bloom_level": "Apply", "options": [{"key": "A", "text": "0.05 Ω", "is_correct": true}, {"key": "B", "text": "0.5 Ω", "is_correct": false}, {"key": "C", "text": "5 Ω", "is_correct": false}, {"key": "D", "text": "50 Ω", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Check your calculation — this value is 10 times too large.", "misconception": "Arithmetic error in division"}, {"option_key": "C", "hint": "A 5 Ω shunt would not bypass enough current for a 5 A range.", "misconception": "Not applying the shunt formula correctly"}, {"option_key": "D", "hint": "Equal resistance to the galvanometer would only double the range, not increase it 1000-fold.", "misconception": "Thinking equal parallel resistance suffices"}]}}, {"chapter_id": "cuet-phy-current-electricity", "topic_id": "cuet-phy-current-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "multiple-choice", "difficulty": "medium", "question_text": "A galvanometer has a resistance of 100 Ω and gives full-scale deflection for 10 mA. To convert it into a voltmeter of range 100 V, the resistance to be connected in series is:", "explanation": "R = V/Ig - G = 100/(10 × 10⁻³) - 100 = 10000 - 100 = 9900 Ω. A high resistance in series limits the current through the galvanometer to its full-scale deflection value when the full voltage is applied.", "correct_answer": "D", "concept_tags": ["voltmeter-conversion", "series-resistance", "numerical"], "payload": {"question_id": "cuet-phy-current-instruments-06", "subtopic": "voltmeter conversion (high resistance in series)", "topic_name": "Measuring Instruments", "bloom_level": "Apply", "options": [{"key": "A", "text": "9900 Ω", "is_correct": false}, {"key": "B", "text": "10000 Ω", "is_correct": false}, {"key": "C", "text": "9,900 Ω", "is_correct": false}, {"key": "D", "text": "9900 Ω", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This is identical to D — but check if one option is distinguished differently in the original.", "misconception": "Reading options carelessly"}, {"option_key": "B", "hint": "10000 Ω is V/Ig but forgets to subtract galvanometer resistance G.", "misconception": "Forgetting to subtract galvanometer resistance"}, {"option_key": "C", "hint": "Same numerical value as D with different formatting — verify the exact answer.", "misconception": "Formatting confusion"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A body has a charge of −3.2 × 10⁻¹⁸ C. The number of excess electrons on the body is:", "explanation": "Number of excess electrons = Total charge / Charge of one electron = (3.2 × 10⁻¹⁸) / (1.6 × 10⁻¹⁹) = 20. The negative sign indicates excess electrons. So the body has 20 excess electrons.", "correct_answer": "B", "concept_tags": ["quantization", "electron-count"], "payload": {"question_id": "cuet-phy-elec-coulomb-01", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "10", "is_correct": false}, {"key": "B", "text": "20", "is_correct": true}, {"key": "C", "text": "30", "is_correct": false}, {"key": "D", "text": "200", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "10 × 1.6 × 10⁻¹⁹ = 1.6 × 10⁻¹⁸ C, which doesn''t match the given charge of 3.2 × 10⁻¹⁸ C.", "misconception": "Arithmetic error in division"}, {"option_key": "C", "hint": "30 × 1.6 × 10⁻¹⁹ = 4.8 × 10⁻¹⁸ C, which exceeds the given charge.", "misconception": null}, {"option_key": "D", "hint": "200 would give 200 × 1.6 × 10⁻¹⁹ = 3.2 × 10⁻¹⁷ C — an order of magnitude too large.", "misconception": "Error in handling powers of 10"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Which of the following is the smallest unit of charge found in nature (free state)?", "explanation": "The smallest unit of free charge in nature is the electronic charge, e = 1.6 × 10⁻¹⁹ C. Quarks carry fractional charges (e/3, 2e/3) but they do not exist in free state — they are always confined within hadrons. Hence, the electron charge is the smallest free charge.", "correct_answer": "C", "concept_tags": ["quantization-of-charge", "electronic-charge"], "payload": {"question_id": "cuet-phy-elec-coulomb-02", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "1 coulomb", "is_correct": false}, {"key": "B", "text": "1 microcoulomb", "is_correct": false}, {"key": "C", "text": "1.6 × 10⁻¹⁹ C", "is_correct": true}, {"key": "D", "text": "1.6 × 10⁻²⁰ C", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1 coulomb is a macroscopic unit — it equals ~6.25 × 10¹⁸ electron charges, far too large to be the smallest.", "misconception": "Thinking the SI unit itself is the smallest charge"}, {"option_key": "B", "hint": "1 μC = 10⁻⁶ C is still billions of electron charges, not the fundamental unit.", "misconception": null}, {"option_key": "D", "hint": "This value doesn''t correspond to any fundamental charge — the correct value is 1.6 × 10⁻¹⁹ C, not 10⁻²⁰.", "misconception": "Confusion in the power of ten"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In the process of charging by induction, the total charge of the system:", "explanation": "Charging by induction does not involve transfer of charge from the charging body. The induced body''s charges get redistributed, and when grounded, opposite charges flow in/out. The charging body retains its original charge throughout. The total charge of the complete system remains conserved.", "correct_answer": "D", "concept_tags": ["charging-by-induction", "conservation-of-charge"], "payload": {"question_id": "cuet-phy-elec-coulomb-03", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Increases", "is_correct": false}, {"key": "B", "text": "Decreases", "is_correct": false}, {"key": "C", "text": "Becomes zero", "is_correct": false}, {"key": "D", "text": "Remains conserved", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Charge cannot be created — the law of conservation of charge prohibits any increase in total charge.", "misconception": "Thinking induction creates new charges"}, {"option_key": "B", "hint": "Charge is never destroyed in any process. The total charge of the universe is constant.", "misconception": "Confusing redistribution with destruction"}, {"option_key": "C", "hint": "Total charge becoming zero would violate conservation — if the charging body had charge Q, it still has Q after induction.", "misconception": "Thinking induced charges cancel the source charge"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Two glass rods, each rubbed with silk, are brought close to each other. They will:", "explanation": "Both glass rods acquire the same type of positive charge when rubbed with silk. Like charges repel each other, so the two rods will repel.", "correct_answer": "B", "concept_tags": ["like-charges", "charging-by-friction", "repulsion"], "payload": {"question_id": "cuet-phy-elec-coulomb-04", "subtopic": "Properties of electric charge", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "Attract each other", "is_correct": false}, {"key": "B", "text": "Repel each other", "is_correct": true}, {"key": "C", "text": "First attract then repel", "is_correct": false}, {"key": "D", "text": "Have no effect on each other", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Attraction occurs between unlike charges. Both rods rubbed with silk acquire the same sign (positive), so they cannot attract.", "misconception": "Confusing like and unlike charge interactions"}, {"option_key": "C", "hint": "There is no mechanism for alternating attraction and repulsion between static charges of the same sign.", "misconception": null}, {"option_key": "D", "hint": "Charged bodies always exert electrostatic forces on each other — they cannot be neutral to one another.", "misconception": "Thinking charged bodies may not interact"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The dimensional formula of permittivity of free space (ε₀) is:", "explanation": "From Coulomb''s law, F = q₁q₂/(4πε₀r²), we get ε₀ = q₁q₂/(4πFr²). Dimensions: [A²T²]/([MLT⁻²][L²]) = [M⁻¹L⁻³T⁴A²]. This can also be derived from ε₀ = 1/(μ₀c²).", "correct_answer": "C", "concept_tags": ["permittivity", "dimensional-analysis", "SI-units"], "payload": {"question_id": "cuet-phy-elec-coulomb-05", "subtopic": "Coulomb''s constant and permittivity", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "[ML³T⁻⁴A⁻²]", "is_correct": false}, {"key": "B", "text": "[M⁻¹L⁻³T³A²]", "is_correct": false}, {"key": "C", "text": "[M⁻¹L⁻³T⁴A²]", "is_correct": true}, {"key": "D", "text": "[MLT⁻²A⁻²]", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This has positive powers of M and L, which would give units of energy × length. Permittivity has inverse mass and inverse length cubed.", "misconception": "Inverting the formula — using dimensions of 1/ε₀ instead of ε₀"}, {"option_key": "B", "hint": "The time exponent should be T⁴, not T³. This comes from charge² = (AT)² = A²T² in the numerator.", "misconception": "Forgetting that charge = current × time, so q² contributes T² not T"}, {"option_key": "D", "hint": "These are the dimensions of force/current², not permittivity. Permittivity has negative powers of M.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two charges Q₁ and Q₂ are separated by a distance d. A third charge Q₃ is placed between them on the line joining them such that the system is in equilibrium. The ratio Q₁/Q₂ must be:", "explanation": "For equilibrium, Q₃ must be between Q₁ and Q₂ (so they must be like charges). If Q₃ is at distance x from Q₁, then kQ₁Q₃/x² = kQ₂Q₃/(d−x)². This gives Q₁/Q₂ = x²/(d−x)². The ratio depends on x, but importantly Q₁/Q₂ must be positive (both same sign). The exact ratio is determined by the position of Q₃.", "correct_answer": "A", "concept_tags": ["equilibrium", "coulomb-law", "charge-configuration"], "payload": {"question_id": "cuet-phy-elec-coulomb-06", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "Positive (both charges must have the same sign)", "is_correct": true}, {"key": "B", "text": "Negative (charges must have opposite signs)", "is_correct": false}, {"key": "C", "text": "Equal to 1 (charges must be equal)", "is_correct": false}, {"key": "D", "text": "Can be any value (no restriction)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "If Q₁ and Q₂ have opposite signs, they attract each other. No position of Q₃ between them can balance both forces — it would be pushed toward one side.", "misconception": "Not considering force directions for unlike charges"}, {"option_key": "C", "hint": "Q₁ and Q₂ need not be equal — they just need to be the same sign. Unequal like charges can still have an equilibrium point (just not at the midpoint).", "misconception": "Assuming equilibrium requires equal charges"}, {"option_key": "D", "hint": "There is definitely a restriction — opposite charges cannot produce equilibrium for a charge placed between them.", "misconception": "Ignoring the direction of forces in equilibrium analysis"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The ratio of the electrostatic force to the gravitational force between an electron and a proton is of the order of:", "explanation": "Electrostatic force: Fe = ke²/r². Gravitational force: Fg = Gmemp/r². The ratio Fe/Fg = ke²/(Gmemp) ≈ (9×10⁹)(1.6×10⁻¹⁹)²/[(6.67×10⁻¹¹)(9.1×10⁻³¹)(1.67×10⁻²⁷)] ≈ 2.3×10³⁹. This shows electrostatic force is enormously stronger than gravity at the atomic scale.", "correct_answer": "D", "concept_tags": ["coulomb-vs-gravity", "force-comparison"], "payload": {"question_id": "cuet-phy-elec-coulomb-07", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "10⁹", "is_correct": false}, {"key": "B", "text": "10¹⁸", "is_correct": false}, {"key": "C", "text": "10²⁷", "is_correct": false}, {"key": "D", "text": "10³⁹", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "10⁹ is far too small — this would mean the two forces are relatively close, but electrostatic force is overwhelmingly stronger.", "misconception": "Confusing the magnitude of k itself with the force ratio"}, {"option_key": "B", "hint": "10¹⁸ is still about 21 orders of magnitude too small. The actual ratio involves masses in the denominator which are extremely tiny.", "misconception": null}, {"option_key": "C", "hint": "10²⁷ is closer but still ~12 orders too small. The product memp in the denominator is ~10⁻⁵⁸, which pushes the ratio much higher.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The force between two charges in vacuum is F. If the entire space between them is filled with a medium of relative permittivity εᵣ = 4, the new force is:", "explanation": "In a dielectric medium, the force between charges becomes F'' = F/εᵣ. Here εᵣ = 4, so F'' = F/4. The dielectric reduces the electrostatic force because the medium gets polarised and partially cancels the applied field.", "correct_answer": "A", "concept_tags": ["dielectric-medium", "permittivity", "force-reduction"], "payload": {"question_id": "cuet-phy-elec-coulomb-08", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "F/4", "is_correct": true}, {"key": "B", "text": "4F", "is_correct": false}, {"key": "C", "text": "F/16", "is_correct": false}, {"key": "D", "text": "16F", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The dielectric reduces the force, not increases it. Multiplying by εᵣ would mean the medium strengthens the force, which is incorrect.", "misconception": "Confusing whether εᵣ goes in numerator or denominator"}, {"option_key": "C", "hint": "F/16 would apply if the force were divided by εᵣ² = 16, but Coulomb''s law divides by εᵣ (first power), not εᵣ².", "misconception": "Incorrectly squaring the dielectric constant"}, {"option_key": "D", "hint": "16F is εᵣ² times the original force — both the direction (increase) and the power are wrong.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A charge q is placed at the centre of a line joining two equal charges Q. The system of three charges will be in equilibrium if q equals:", "explanation": "For the charge Q at one end to be in equilibrium: Force due to the other Q (repulsive) = Force due to q (attractive, so q must be negative). kQ²/(2a)² = kqQ/a² → Q/4 = q → q = −Q/4. The negative sign is essential because q must attract Q to counterbalance the repulsion from the other Q.", "correct_answer": "B", "concept_tags": ["equilibrium", "three-charge-system"], "payload": {"question_id": "cuet-phy-elec-coulomb-09", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "−Q/2", "is_correct": false}, {"key": "B", "text": "−Q/4", "is_correct": true}, {"key": "C", "text": "+Q/4", "is_correct": false}, {"key": "D", "text": "+Q/2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "−Q/2 would make the attractive force on Q from q twice as large as needed, since kQ(Q/2)/a² ≠ kQ²/4a².", "misconception": "Error in setting up force balance — not accounting for the 2a distance properly"}, {"option_key": "C", "hint": "A positive charge at the centre would repel both Q charges outward, adding to the instability rather than creating equilibrium.", "misconception": "Forgetting that q must attract Q to counter the repulsion"}, {"option_key": "D", "hint": "+Q/2 at the centre would push both Q charges apart — equilibrium requires an attractive (negative) charge at the centre.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two point charges attract each other with force F at a certain distance. If the magnitude of one charge is doubled and the distance is tripled, the new force is:", "explanation": "Original: F = kq₁q₂/r². New: F'' = k(2q₁)q₂/(3r)² = 2kq₁q₂/9r² = 2F/9. Doubling one charge doubles the force, tripling the distance reduces it by 9, net effect is 2/9.", "correct_answer": "B", "concept_tags": ["coulomb-law", "inverse-square", "proportionality"], "payload": {"question_id": "cuet-phy-elec-coulomb-10", "subtopic": "Coulomb''s law applications", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "2F/3", "is_correct": false}, {"key": "B", "text": "2F/9", "is_correct": true}, {"key": "C", "text": "F/9", "is_correct": false}, {"key": "D", "text": "F/3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "2F/3 results from dividing by 3 (first power) instead of 3² = 9. Coulomb''s law has inverse square dependence.", "misconception": "Using inverse distance instead of inverse square distance"}, {"option_key": "C", "hint": "F/9 accounts for tripling the distance but forgets that one charge was also doubled, which should multiply by 2.", "misconception": "Ignoring the change in charge magnitude"}, {"option_key": "D", "hint": "F/3 uses neither the correct distance factor (should be 9, not 3) nor accounts for the charge doubling properly.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A charge Q is divided into two parts q and (Q − q). For the electrostatic force between them to be maximum when placed at a fixed distance, q should be:", "explanation": "Force F = kq(Q−q)/r² = k(qQ − q²)/r². For maximum F, dF/dq = 0 → Q − 2q = 0 → q = Q/2. So the force is maximum when the charge is divided equally. Second derivative d²F/dq² = −2k/r² < 0, confirming maximum.", "correct_answer": "C", "concept_tags": ["optimization", "coulomb-force", "maxima"], "payload": {"question_id": "cuet-phy-elec-coulomb-11", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "Q/4", "is_correct": false}, {"key": "B", "text": "Q/3", "is_correct": false}, {"key": "C", "text": "Q/2", "is_correct": true}, {"key": "D", "text": "Q", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "With q = Q/4, the product q(Q−q) = Q/4 × 3Q/4 = 3Q²/16 = 0.1875Q². This is less than the maximum possible value.", "misconception": null}, {"option_key": "B", "hint": "With q = Q/3, the product = Q/3 × 2Q/3 = 2Q²/9 ≈ 0.222Q², still less than the maximum of Q²/4 = 0.25Q².", "misconception": null}, {"option_key": "D", "hint": "If q = Q, then the other part is Q − Q = 0, giving zero force. This is actually the minimum, not maximum.", "misconception": "Not realizing that giving all charge to one part leaves nothing for the other"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two point charges +4q and +q are placed at a distance L apart. The null point (where the net electric field is zero) lies:", "explanation": "The null point lies between the charges on the line joining them, closer to the smaller charge. Let it be at distance x from +q. At null point: kq/x² = k(4q)/(L−x)² → (L−x)² = 4x² → L−x = 2x → x = L/3. So the null point is at L/3 from +q (or 2L/3 from +4q).", "correct_answer": "B", "concept_tags": ["null-point", "electric-field", "superposition"], "payload": {"question_id": "cuet-phy-elec-coulomb-12", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "At L/2 from +4q (midpoint)", "is_correct": false}, {"key": "B", "text": "At L/3 from +q", "is_correct": true}, {"key": "C", "text": "At L/3 from +4q", "is_correct": false}, {"key": "D", "text": "Outside the charges, beyond +q", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The midpoint would only be the null point if both charges were equal. Since 4q > q, the null point shifts toward the weaker charge.", "misconception": "Assuming null point is always at the midpoint"}, {"option_key": "C", "hint": "L/3 from the larger charge (+4q) means 2L/3 from +q. At this point, the stronger charge is closer, making its field dominant — not a null point.", "misconception": "Placing the null point closer to the larger charge instead of the smaller"}, {"option_key": "D", "hint": "For two like charges, the null point always lies between them. It lies outside only when charges have opposite signs.", "misconception": "Confusing null point location for like vs unlike charges"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If each of two point charges is doubled and the distance between them is halved, the electrostatic force between them becomes:", "explanation": "Original force: F = kq₁q₂/r². New force: F'' = k(2q₁)(2q₂)/(r/2)² = k × 4q₁q₂ / (r²/4) = 16 × kq₁q₂/r² = 16F. The force increases by a factor of 16.", "correct_answer": "C", "concept_tags": ["coulomb-law", "proportionality", "numerical"], "payload": {"question_id": "cuet-phy-elec-coulomb-13", "subtopic": "Coulomb''s law applications", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "4F", "is_correct": false}, {"key": "B", "text": "8F", "is_correct": false}, {"key": "C", "text": "16F", "is_correct": true}, {"key": "D", "text": "32F", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "4F accounts for doubling both charges (2×2=4) but ignores the effect of halving the distance, which adds another factor of 4.", "misconception": "Forgetting the distance factor"}, {"option_key": "B", "hint": "8F might come from 2×2×2=8, but halving distance gives 1/(1/2)²=4, not 2. Total should be 4×4=16.", "misconception": "Treating distance halving as a factor of 2 instead of 4"}, {"option_key": "D", "hint": "32F would require an extra factor of 2 beyond 16 — there''s no physical reason for this.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The dielectric constant (relative permittivity) of a perfect conductor is:", "explanation": "Inside a perfect conductor, the electric field is always zero. Since K = E_vacuum/E_medium, for the field to be zero inside the conductor, K must be infinite. Alternatively, a conductor can be thought of as a medium that completely screens the electric field, requiring K → ∞.", "correct_answer": "D", "concept_tags": ["dielectric-constant", "conductor", "permittivity"], "payload": {"question_id": "cuet-phy-elec-coulomb-14", "subtopic": "Dielectrics and conductors", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Zero", "is_correct": false}, {"key": "B", "text": "1", "is_correct": false}, {"key": "C", "text": "Negative", "is_correct": false}, {"key": "D", "text": "Infinity", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "K = 0 would mean ε = 0, which would imply infinite electric field inside the medium — the opposite of what happens in a conductor.", "misconception": "Confusing zero field inside conductor with zero dielectric constant"}, {"option_key": "B", "hint": "K = 1 corresponds to vacuum/air. A conductor has much stronger polarisation response than vacuum.", "misconception": "Thinking conductor behaves like vacuum"}, {"option_key": "C", "hint": "Dielectric constant is always positive. A negative value would imply the medium reverses the field direction, which doesn''t happen with normal conductors.", "misconception": null}]}}]'::jsonb, 'deploy-2026-03-05-b03');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two identical metallic spheres carrying charges of +40 μC and −10 μC are brought into contact and then separated. The charge on each sphere after separation is:", "explanation": "When two identical conducting spheres are brought into contact, the total charge distributes equally. Total charge = +40 + (−10) = +30 μC. Since the spheres are identical, each gets 30/2 = +15 μC after separation.", "correct_answer": "C", "concept_tags": ["charge-sharing", "conservation-of-charge", "conductors"], "payload": {"question_id": "cuet-phy-elec-coulomb-15", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "+20 μC", "is_correct": false}, {"key": "B", "text": "+25 μC", "is_correct": false}, {"key": "C", "text": "+15 μC", "is_correct": true}, {"key": "D", "text": "+30 μC", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "+20 μC would mean the average of absolute values (40+10)/2, ignoring that charges are algebraically added (signs matter).", "misconception": "Averaging absolute values instead of algebraic sum"}, {"option_key": "B", "hint": "+25 μC each would give a total of +50 μC, violating charge conservation (total is only +30 μC).", "misconception": null}, {"option_key": "D", "hint": "+30 μC on each sphere would give a total of +60 μC, double the actual total charge — charge is not doubled upon contact.", "misconception": "Forgetting to divide the total equally"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "When a glass rod is rubbed with silk, the rod becomes positively charged because:", "explanation": "During rubbing, electrons (not protons) are transferred from the glass rod to the silk. The rod loses electrons and becomes positively charged, while the silk gains those electrons and becomes negatively charged. Protons, being bound in the nucleus, do not transfer.", "correct_answer": "A", "concept_tags": ["charging-by-friction", "electron-transfer", "triboelectric"], "payload": {"question_id": "cuet-phy-elec-coulomb-16", "subtopic": "Methods of charging", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Electrons are transferred from the rod to the silk", "is_correct": true}, {"key": "B", "text": "Protons are transferred from the silk to the rod", "is_correct": false}, {"key": "C", "text": "Protons are created on the rod", "is_correct": false}, {"key": "D", "text": "Neutrons are removed from the rod", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Protons are tightly bound in the nucleus and cannot be transferred by rubbing. Only electrons, which are in outer shells, can move.", "misconception": "Thinking protons can be transferred between materials"}, {"option_key": "C", "hint": "Charge is conserved — it cannot be created or destroyed. Rubbing only transfers existing charges.", "misconception": "Thinking charge can be created from nothing"}, {"option_key": "D", "hint": "Neutrons carry no charge, so removing them would not make the rod positively charged.", "misconception": "Confusing the role of neutrons in charge"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two identical small conducting spheres have charges +3Q and −Q. They are first touched together and then separated by a distance d. The force between them after separation, compared to the initial force (at the same distance d), is:", "explanation": "Initial force: F₁ = k(3Q)(Q)/d² = 3kQ²/d² (attractive). After touching: total charge = 3Q + (−Q) = 2Q, shared equally → each gets +Q. New force: F₂ = k(Q)(Q)/d² = kQ²/d² (repulsive). Ratio: F₂/F₁ = 1/3. Also, the force changed from attractive to repulsive.", "correct_answer": "D", "concept_tags": ["charge-sharing", "force-comparison", "attraction-repulsion"], "payload": {"question_id": "cuet-phy-elec-coulomb-17", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "Same magnitude and same nature", "is_correct": false}, {"key": "B", "text": "1/3 of initial magnitude and same nature (attractive)", "is_correct": false}, {"key": "C", "text": "3 times the initial magnitude and repulsive", "is_correct": false}, {"key": "D", "text": "1/3 of initial magnitude and opposite nature (now repulsive)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The charges change from (+3Q, −Q) to (+Q, +Q). Both the product of charges and the sign change, so the force cannot remain the same.", "misconception": "Thinking charge sharing doesn''t affect the force"}, {"option_key": "B", "hint": "The magnitude ratio (1/3) is correct, but the nature changes — initially opposite charges (attractive) become same charges (repulsive) after contact.", "misconception": "Calculating magnitude correctly but forgetting to check if nature changes"}, {"option_key": "C", "hint": "Q²/d² is 1/3 of 3Q²/d², not 3 times. The force decreases, it doesn''t triple.", "misconception": "Inverting the ratio"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Eight identical point charges q are placed at the eight corners of a cube of side a. The electrostatic force on any one charge due to the remaining seven is:", "explanation": "Consider one corner charge. The 7 other charges are at distances: 3 face-diagonal neighbours at a√2, 3 edge neighbours at a, and 1 body-diagonal neighbour at a√3. By symmetry, the net force on the corner charge is directed along the body diagonal (away from the cube centre). The magnitude requires vector addition of all 7 forces along this direction using direction cosines.", "correct_answer": "C", "concept_tags": ["cube-symmetry", "superposition", "three-dimensions"], "payload": {"question_id": "cuet-phy-elec-coulomb-18", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "7kq²/a² directed toward the centre", "is_correct": false}, {"key": "B", "text": "Zero, by symmetry", "is_correct": false}, {"key": "C", "text": "Directed along the body diagonal, away from the centre", "is_correct": true}, {"key": "D", "text": "Directed along the edge of the cube", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The charges are all positive (like charges), so they repel — the force must be away from the cube, not toward the centre.", "misconception": "Getting the direction wrong for repulsive forces"}, {"option_key": "B", "hint": "The corner charge is NOT at the centre of the arrangement. The 7 other charges are NOT symmetrically distributed around a corner — there are more charges on one side.", "misconception": "Incorrectly applying symmetry — symmetry only gives zero at the centre"}, {"option_key": "D", "hint": "The cubic symmetry at a corner has three-fold symmetry about the body diagonal, so the net force must lie along this diagonal, not along any single edge.", "misconception": "Not recognising the 3-fold rotational symmetry about the body diagonal"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A charge Q is uniformly distributed along a semi-circular arc of radius R. The magnitude of the electric field at the centre of curvature is:", "explanation": "Linear charge density λ = Q/(πR). Consider a small element dθ at angle θ from the axis of symmetry. Its field at centre: dE = kλRdθ/R² = kλdθ/R. By symmetry, only the component along the axis of symmetry (perpendicular bisector of the diameter) survives. E = ∫₀^π (kλ/R)sinθ dθ = (kλ/R)[-cosθ]₀^π = 2kλ/R = 2k(Q/πR)/R = 2kQ/(πR²).", "correct_answer": "C", "concept_tags": ["continuous-distribution", "semi-circular-arc", "integration"], "payload": {"question_id": "cuet-phy-elec-coulomb-19", "subtopic": "Continuous charge distributions", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "kQ/R²", "is_correct": false}, {"key": "B", "text": "kQ/(πR²)", "is_correct": false}, {"key": "C", "text": "2kQ/(πR²)", "is_correct": true}, {"key": "D", "text": "Zero", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "kQ/R² treats the entire semi-circular charge as a point charge at distance R, ignoring the angular distribution.", "misconception": "Treating distributed charge as a point charge"}, {"option_key": "B", "hint": "kQ/(πR²) is missing the factor of 2 that comes from the integration of sinθ over 0 to π: ∫sinθ dθ = 2.", "misconception": "Integration error — forgetting the factor of 2"}, {"option_key": "D", "hint": "Zero would be the field at the centre of a full circle, not a semi-circle. The semi-circle has a net field along its symmetry axis.", "misconception": "Confusing semi-circular arc with full circular arc"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two isolated conducting spheres of radii R and 2R carry charges Q and 2Q respectively. They are connected by a thin conducting wire and then disconnected. The charge on the smaller sphere after disconnection is:", "explanation": "When connected, charge flows until both spheres reach the same potential. Total charge = Q + 2Q = 3Q. At equal potential: V₁ = V₂ → kq₁/R = kq₂/(2R) → q₂ = 2q₁. With q₁ + q₂ = 3Q: q₁ + 2q₁ = 3Q → q₁ = Q. The smaller sphere ends up with charge Q (same as its original charge, coincidentally).", "correct_answer": "A", "concept_tags": ["conducting-spheres", "charge-sharing", "equal-potential"], "payload": {"question_id": "cuet-phy-elec-coulomb-20", "subtopic": "Charge redistribution between conductors", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "Q", "is_correct": true}, {"key": "B", "text": "3Q/2", "is_correct": false}, {"key": "C", "text": "2Q", "is_correct": false}, {"key": "D", "text": "Q/2", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "3Q/2 assumes equal charge on each sphere, but connected conductors equalise potential, not charge. Charge distributes proportional to radius.", "misconception": "Assuming equal charge instead of equal potential"}, {"option_key": "C", "hint": "2Q on the smaller sphere would leave Q on the larger, giving V_small/V_large = (2Q/R)/(Q/2R) = 4, violating equal potential.", "misconception": null}, {"option_key": "D", "hint": "Q/2 on smaller means 5Q/2 on larger. V_small/V_large = (Q/2R)/(5Q/4R) = 2/5, not equal.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): A charged body can attract an uncharged body.\nReason (R): When a charged body is brought near an uncharged body, it induces opposite charge on the nearer surface of the uncharged body.", "explanation": "The assertion is true — a charged body (say positively charged) brought near an uncharged conductor induces negative charge on the nearer surface and positive charge on the far surface. The attractive force on the nearer induced charge is stronger than the repulsive force on the farther induced charge (since force ∝ 1/r²). So there is a net attraction. The reason correctly explains this mechanism. Both A and R are true, and R is the correct explanation of A.", "correct_answer": "A", "concept_tags": ["induction", "attraction-uncharged-body"], "payload": {"question_id": "cuet-phy-elec-coulomb-25", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The induced opposite charge on the nearer surface is precisely the mechanism that causes attraction — R directly explains A.", "misconception": "Thinking the reason is unrelated to the assertion"}, {"option_key": "C", "hint": "The reason is factually correct — induction does create opposite charges on the nearer surface. This is a well-established phenomenon.", "misconception": "Doubting the mechanism of electrostatic induction"}, {"option_key": "D", "hint": "The assertion is definitely correct — it''s a commonly observed phenomenon. Rub a comb on hair and it attracts paper bits (which are uncharged).", "misconception": "Thinking only charged bodies can be attracted"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): A sensitive gold-leaf electroscope can detect charge quantization at macroscopic scales.\nReason (R): The elementary charge e = 1.6 × 10⁻¹⁹ C is extremely small compared to charges typically encountered in daily life.", "explanation": "A is FALSE: at macroscopic scales, charges are so large (of order μC or more) that the discrete nature (quantization) of charge is not observable — charge appears continuous. R is TRUE: e is indeed extremely small compared to macroscopic charges, which is precisely why quantization is undetectable at large scales. Since A is incorrect and R is correct, the answer is D.", "correct_answer": "D", "concept_tags": ["quantization", "macroscopic-charge", "gold-leaf-electroscope"], "payload": {"question_id": "cuet-phy-elec-coulomb-26", "subtopic": "Quantization of charge", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The assertion is incorrect — quantization cannot be detected at macroscopic scales because the elementary charge is too small relative to everyday charges.", "misconception": "Thinking quantization is easily observable with a gold-leaf electroscope"}, {"option_key": "B", "hint": "A is false, not true. A gold-leaf electroscope cannot detect individual electron charges.", "misconception": null}, {"option_key": "C", "hint": "R is actually correct — e = 1.6 × 10⁻¹⁹ C is indeed extremely small compared to typical macroscopic charges.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): Coulomb''s law and Newton''s law of gravitation have the same mathematical form (inverse square law), but the electrostatic force can be both attractive and repulsive.\nReason (R): Electric charge comes in two types (positive and negative) whereas mass is always positive.", "explanation": "Assertion is true: both F = kq₁q₂/r² and F = Gm₁m₂/r² follow the inverse square law, but gravity is always attractive while electrostatic force can be attractive (unlike charges) or repulsive (like charges). Reason is also true: the existence of two types of charge (+ and −) allows for both attraction and repulsion, while mass being always positive means gravity can only be attractive. R correctly explains why electrostatic force has dual nature while gravity doesn''t.", "correct_answer": "A", "concept_tags": ["coulomb-vs-gravity", "charge-types", "force-nature"], "payload": {"question_id": "cuet-phy-elec-coulomb-27", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The existence of two charge types is exactly what causes the electrostatic force to be either attractive or repulsive — R directly explains the dual nature mentioned in A.", "misconception": "Missing the causal connection between charge duality and force nature"}, {"option_key": "C", "hint": "The reason is factually correct — charge has two types (positive and negative) while mass is always positive. This is basic physics.", "misconception": null}, {"option_key": "D", "hint": "The assertion is factually correct — both laws follow inverse square dependence, and electrostatic force can be attractive or repulsive unlike gravity.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): Coulomb''s law accurately predicts the force between two charged bodies of any shape and size.\nReason (R): Coulomb''s law is derived for point charges and works accurately only when the size of the charged bodies is much smaller than the distance between them.", "explanation": "A is FALSE: Coulomb''s law in its standard form F = kq₁q₂/r² is strictly valid only for point charges (or when bodies are very small compared to separation). For extended bodies, charge distribution matters and the simple formula is inadequate. R is TRUE: it correctly states the limitation. Since A is wrong and R is right, the answer is D.", "correct_answer": "D", "concept_tags": ["coulomb-law-limitations", "point-charge-approximation"], "payload": {"question_id": "cuet-phy-elec-coulomb-28", "subtopic": "Validity conditions of Coulomb''s law", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "A is false — Coulomb''s law does not work for bodies of any shape/size. For large or close conductors, charge redistribution invalidates the point-charge formula.", "misconception": "Thinking Coulomb''s law applies universally to all shapes"}, {"option_key": "B", "hint": "A is false, so this option cannot be correct.", "misconception": null}, {"option_key": "C", "hint": "R is factually correct — it accurately describes the point-charge requirement of Coulomb''s law.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the charging method in Column I with its key characteristic in Column II:\n\nColumn I:\nA. Charging by friction\nB. Charging by conduction\nC. Charging by induction\nD. Charging by a Van de Graaff generator\n\nColumn II:\n1. Charge accumulation on a hollow sphere using a belt\n2. Both bodies acquire equal and opposite charges\n3. The charged body transfers charge to the uncharged body on contact\n4. The charged body induces charge separation without contact", "explanation": "Friction (A) involves rubbing two bodies — both acquire equal and opposite charges → A-2. Conduction (B) involves touching a charged body to an uncharged one — charge flows on contact → B-3. Induction (C) involves bringing a charged body near an uncharged conductor without contact → C-4. Van de Graaff generator (D) uses a moving belt to accumulate charge on a hollow metal sphere → D-1.", "correct_answer": "C", "concept_tags": ["charging-methods", "friction", "conduction", "induction"], "payload": {"question_id": "cuet-phy-elec-coulomb-29", "subtopic": "Methods of charging", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "A-3, B-2, C-4, D-1", "is_correct": false}, {"key": "B", "text": "A-2, B-4, C-3, D-1", "is_correct": false}, {"key": "C", "text": "A-2, B-3, C-4, D-1", "is_correct": true}, {"key": "D", "text": "A-4, B-3, C-2, D-1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This assigns ''charge transfer on contact'' (3) to friction and ''equal and opposite charges'' (2) to conduction. In friction, both bodies get equal opposite charges; conduction involves contact transfer.", "misconception": "Swapping friction and conduction characteristics"}, {"option_key": "B", "hint": "This assigns ''no contact'' (4) to conduction, but conduction requires physical contact.", "misconception": "Confusing conduction (contact required) with induction (no contact)"}, {"option_key": "D", "hint": "This assigns ''no contact'' (4) to friction, but friction requires vigorous rubbing (contact).", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the physical situation in Column I with the correct force expression in Column II:\n\nColumn I:\nA. Two charges q in vacuum at distance d\nB. Two charges q in medium (K=4) at distance d\nC. Two charges q in vacuum at distance 2d\nD. Charges 2q and q in vacuum at distance d\n\nColumn II:\n1. kq²/(4d²)\n2. 2kq²/d²\n3. kq²/(4d²)\n4. kq²/d²", "explanation": "A: F = kq²/d² → A-4. B: F = kq²/(Kd²) = kq²/(4d²) → B-1 (or B-3, since items 1 and 3 are identical). C: F = kq²/(2d)² = kq²/(4d²) → C-3 (or C-1). D: F = k(2q)(q)/d² = 2kq²/d² → D-2. Note: items 1 and 3 have the same expression, so B and C both map to kq²/(4d²).", "correct_answer": "B", "concept_tags": ["coulomb-law-variations", "dielectric", "distance-scaling"], "payload": {"question_id": "cuet-phy-elec-coulomb-30", "subtopic": "Coulomb''s law applications", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "A-4, B-2, C-1, D-3", "is_correct": false}, {"key": "B", "text": "A-4, B-1, C-3, D-2", "is_correct": true}, {"key": "C", "text": "A-2, B-4, C-3, D-1", "is_correct": false}, {"key": "D", "text": "A-4, B-3, C-2, D-1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This assigns 2kq²/d² to situation B (medium K=4), but a medium reduces the force, so B cannot give the largest force expression.", "misconception": "Thinking a dielectric increases the force"}, {"option_key": "C", "hint": "This assigns kq²/d² (full vacuum force) to two charges q in vacuum at 2d — but doubling distance reduces force by 4.", "misconception": "Ignoring the effect of doubling the distance"}, {"option_key": "D", "hint": "This maps D (charges 2q and q) to kq²/(4d²), but the product 2q×q = 2q² gives 2kq²/d², not kq²/4d².", "misconception": "Not computing the charge product correctly"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The total charge of an isolated system is always conserved, regardless of the interactions within the system.", "explanation": "This is TRUE. Conservation of charge is a fundamental law of physics. In any isolated system, the total electric charge remains constant — charges can be transferred, redistributed, or created in pairs (particle-antiparticle), but the algebraic sum never changes. This has been verified in countless experiments and is as fundamental as conservation of energy.", "correct_answer": "A", "concept_tags": ["conservation-of-charge", "fundamental-law"], "payload": {"question_id": "cuet-phy-elec-coulomb-31", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Conservation of charge is one of the most rigorously tested laws in physics. No experiment has ever found a violation.", "misconception": "Thinking charge conservation can be violated in nuclear reactions or pair production"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Electric charge is an additive quantity — the total charge of a system is the algebraic sum of all individual charges.", "explanation": "This is TRUE. Additivity of charge means the total charge of a system equals the algebraic (not absolute) sum of all charges. For example, if a system has charges +5 μC and −3 μC, the total charge is +2 μC. This property, along with conservation and quantization, is a fundamental property of electric charge.", "correct_answer": "A", "concept_tags": ["additivity", "charge-properties", "algebraic-sum"], "payload": {"question_id": "cuet-phy-elec-coulomb-32", "subtopic": "Properties of electric charge", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Additivity of charge is a well-established property. Unlike some quantities (like mass in relativity), charge adds algebraically in all situations.", "misconception": "Confusing additivity of charge with non-additive quantities"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Coulomb''s law can be applied directly to calculate the force between two charged conducting spheres of finite radius placed close together.", "explanation": "This is FALSE. Coulomb''s law in its standard form F = kq₁q₂/r² applies to point charges. For conducting spheres placed close together, the charge distribution on each sphere gets distorted (induced redistribution) — it is no longer uniform. The charges concentrate on the nearer surfaces (for opposite charges) or redistribute unevenly. To find the exact force, one must account for this non-uniform distribution, not simply use Coulomb''s law with centre-to-centre distance.", "correct_answer": "B", "concept_tags": ["coulomb-law-limitations", "finite-size-effects"], "payload": {"question_id": "cuet-phy-elec-coulomb-33", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Coulomb''s law assumes point charges. For finite-sized conductors placed close together, charge redistribution occurs on the surfaces, making the point-charge approximation invalid.", "misconception": "Assuming Coulomb''s law works for all charge geometries without modification"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The force between two point charges depends on the nature of the medium between them — it decreases when a dielectric is placed between them but increases when they are in vacuum.", "explanation": "This is partially misleading but essentially FALSE as stated. The statement implies the force ''increases in vacuum'' as if vacuum makes it stronger than some baseline — but vacuum IS the reference (maximum force). The force in any medium is F/K where K ≥ 1. The statement''s implication that force ''increases'' in vacuum is incorrect framing. The correct statement: force is maximum in vacuum and decreases in any dielectric medium.", "correct_answer": "B", "concept_tags": ["dielectric-effect", "medium-dependence", "vacuum"], "payload": {"question_id": "cuet-phy-elec-coulomb-34", "subtopic": "Coulomb''s law in different media", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The phrasing ''increases in vacuum'' is misleading. Force is maximum in vacuum — it doesn''t ''increase'' because vacuum is already the reference state (K=1). Any medium only reduces the force.", "misconception": "Thinking vacuum actively increases the force rather than being the baseline"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "easy", "question_text": "The minimum charge that can exist independently in nature is called the _____ charge, and its value is approximately _____.", "explanation": "The minimum independently existing charge is the elementary charge (e), with value approximately 1.6 × 10⁻¹⁹ C. This was first accurately measured by Robert Millikan in his oil-drop experiment (1909). All observable charges are integral multiples of this fundamental unit.", "correct_answer": "D", "concept_tags": ["elementary-charge", "millikan-experiment"], "payload": {"question_id": "cuet-phy-elec-coulomb-35", "subtopic": "Quantization of charge", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "unit; 1 coulomb", "is_correct": false}, {"key": "B", "text": "fractional; 1.6 × 10⁻²⁰ C", "is_correct": false}, {"key": "C", "text": "atomic; 9.1 × 10⁻³¹ kg", "is_correct": false}, {"key": "D", "text": "elementary; 1.6 × 10⁻¹⁹ C", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "1 coulomb is a macroscopic unit of charge (≈6.25 × 10¹⁸ electron charges), far too large to be the minimum charge.", "misconception": "Confusing the SI unit with the fundamental minimum"}, {"option_key": "B", "hint": "1.6 × 10⁻²⁰ C is ten times smaller than the actual elementary charge. Also, charge is not called ''fractional charge''.", "misconception": "Incorrect value of elementary charge"}, {"option_key": "C", "hint": "9.1 × 10⁻³¹ kg is the mass of an electron, not a charge. The units are wrong (kg vs C).", "misconception": "Confusing electron mass with electron charge"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The charge on a body is always an integral multiple of _____, which is known as the quantization of electric charge.", "explanation": "The quantization of electric charge states that the charge on any body is always q = ne, where n is an integer and e = 1.6 × 10⁻¹⁹ C is the elementary charge. This means charge cannot exist in fractions of e (in free state). Robert Millikan''s oil drop experiment provided the first precise measurement of e.", "correct_answer": "D", "concept_tags": ["quantization", "elementary-charge", "millikan"], "payload": {"question_id": "cuet-phy-elec-coulomb-36", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "1 coulomb", "is_correct": false}, {"key": "B", "text": "1 ampere-second", "is_correct": false}, {"key": "C", "text": "1.6 × 10⁻²⁰ C", "is_correct": false}, {"key": "D", "text": "1.6 × 10⁻¹⁹ C (the elementary charge e)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "1 coulomb is far too large to be the quantum of charge — it contains ~6.25 × 10¹⁸ elementary charges.", "misconception": "Confusing the SI unit with the fundamental quantum"}, {"option_key": "B", "hint": "While 1 ampere-second equals 1 coulomb dimensionally, this is the same as option A — it''s the SI unit, not the quantum.", "misconception": null}, {"option_key": "C", "hint": "The correct value is 1.6 × 10⁻¹⁹ C, not 10⁻²⁰. This is one order of magnitude too small.", "misconception": "Error in the exponent"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "In a laboratory experiment, a student uses a Coulomb''s torsion balance to measure the force between two charged pith balls. When the distance between the balls is halved (keeping charges the same), the student observes that the torsion angle quadruples. However, when the student inserts a glass slab (dielectric constant K = 5) between the two balls at the original distance, the torsion angle becomes 1/5th of the original. Based on these observations, which conclusion is correct?", "explanation": "When distance is halved: F'' = kq₁q₂/(d/2)² = 4kq₁q₂/d² = 4F. The force quadruples, so the torsion angle quadruples — consistent with inverse square law. When a dielectric (K = 5) is inserted: F'''' = kq₁q₂/(Kd²) = F/5. The force becomes 1/5th — consistent with the dielectric reducing the force by factor K. Both observations confirm Coulomb''s law: inverse square dependence on distance and linear dependence on dielectric constant.", "correct_answer": "B", "concept_tags": ["coulomb-torsion-balance", "inverse-square", "dielectric"], "payload": {"question_id": "cuet-phy-elec-coulomb-37", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "Only the inverse square law is verified; the dielectric result is anomalous", "is_correct": false}, {"key": "B", "text": "Both observations are consistent with Coulomb''s law — F ∝ 1/r² and F ∝ 1/K", "is_correct": true}, {"key": "C", "text": "The dielectric should have increased the force, not decreased it", "is_correct": false}, {"key": "D", "text": "The force should have become 1/25th with the dielectric, not 1/5th", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The dielectric result (F/K) is a standard prediction of Coulomb''s law — it is not anomalous but expected.", "misconception": "Not knowing how dielectrics affect Coulomb''s law"}, {"option_key": "C", "hint": "Dielectrics always reduce electrostatic force between charges. The polarised medium partially screens the charges, weakening the interaction.", "misconception": "Confusing the effect of a dielectric — it reduces, not increases, the force"}, {"option_key": "D", "hint": "1/25 would mean dividing by K² = 25, but Coulomb''s law divides by K (first power), not K².", "misconception": "Incorrectly squaring the dielectric constant K"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "In an advanced electrostatics lab, two identical insulating spheres A and B carry charges +6Q and −2Q respectively. They are touched together, separated, and then sphere B is touched to an identical uncharged sphere C. After all separations, the charges on A, B, and C respectively are:", "explanation": "Step 1: A (+6Q) and B (−2Q) touch → total = 4Q, each gets +2Q. After separation: A = +2Q, B = +2Q. Step 2: B (+2Q) touches C (0) → total = 2Q, each gets +Q. After separation: B = +Q, C = +Q. Final: A = +2Q, B = +Q, C = +Q.", "correct_answer": "D", "concept_tags": ["charge-sharing", "multiple-steps", "conductors"], "payload": {"question_id": "cuet-phy-elec-coulomb-38", "subtopic": "Charge redistribution", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "+2Q, +2Q, 0", "is_correct": false}, {"key": "B", "text": "+3Q, +Q/2, +Q/2", "is_correct": false}, {"key": "C", "text": "+4Q/3, +4Q/3, +4Q/3", "is_correct": false}, {"key": "D", "text": "+2Q, +Q, +Q", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This only accounts for step 1 (A and B sharing charge) but ignores step 2 (B touching C).", "misconception": "Forgetting the second touching step"}, {"option_key": "B", "hint": "+3Q total ≠ 4Q total. The total charge must be conserved at +6Q + (−2Q) = +4Q throughout.", "misconception": "Arithmetic error in charge conservation"}, {"option_key": "C", "hint": "This assumes all three spheres share charge equally, but A was separated before B touched C. A doesn''t participate in the second sharing.", "misconception": "Assuming all three spheres share charge simultaneously"}]}}]'::jsonb, 'deploy-2026-03-05-b03');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following steps of charging a metal sphere by induction in the correct sequence:\n\n1. Ground the sphere (connect to earth)\n2. Bring a positively charged rod near the sphere (without touching)\n3. Remove the grounding connection\n4. Remove the charged rod\n5. Negative charge remains on the sphere", "explanation": "Correct sequence: First bring the charged rod near (2) → this induces charge separation. Then ground the sphere (1) → positive charges flow to earth, leaving excess negative. Remove ground (3) → excess negative charge is trapped. Remove the rod (4) → negative charge redistributes uniformly. Result: sphere is negatively charged (5).", "correct_answer": "C", "concept_tags": ["induction-charging", "sequence", "grounding"], "payload": {"question_id": "cuet-phy-elec-coulomb-39", "subtopic": "Charging by induction", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "1 → 2 → 3 → 4 → 5", "is_correct": false}, {"key": "B", "text": "2 → 3 → 1 → 4 → 5", "is_correct": false}, {"key": "C", "text": "2 → 1 → 3 → 4 → 5", "is_correct": true}, {"key": "D", "text": "1 → 2 → 4 → 3 → 5", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Grounding first (step 1) without the charged rod nearby has no effect — there''s no induced charge to drain. The rod must be brought close first.", "misconception": "Grounding before bringing the inducing charge"}, {"option_key": "B", "hint": "Removing ground (step 3) before connecting it (step 1) is illogical. You must ground first, then remove the ground.", "misconception": "Mixing up the order of grounding and ungrounding"}, {"option_key": "D", "hint": "Removing the rod (step 4) before removing the ground (step 3) would allow the trapped negative charge to flow back to earth, leaving the sphere uncharged.", "misconception": "Not realising that the ground must be removed BEFORE the rod"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "hard", "question_text": "Arrange the following discoveries/developments in the history of electrostatics in chronological order:\n\n1. Millikan''s oil drop experiment (precise measurement of e)\n2. Coulomb''s torsion balance experiment\n3. Benjamin Franklin''s kite experiment\n4. Discovery of the electron by J.J. Thomson", "explanation": "Chronological order: Benjamin Franklin''s kite experiment (1752) → Coulomb''s torsion balance (1785) → J.J. Thomson discovers the electron (1897) → Millikan''s oil drop experiment (1909). So the sequence is 3 → 2 → 4 → 1.", "correct_answer": "B", "concept_tags": ["history-of-physics", "chronological-order", "electrostatics"], "payload": {"question_id": "cuet-phy-elec-coulomb-40", "subtopic": "Historical development", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "2 → 3 → 4 → 1", "is_correct": false}, {"key": "B", "text": "3 → 2 → 4 → 1", "is_correct": true}, {"key": "C", "text": "3 → 2 → 1 → 4", "is_correct": false}, {"key": "D", "text": "1 → 4 → 2 → 3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Coulomb''s experiment (1785) came after Franklin''s (1752), not before. Franklin predated Coulomb by about 33 years.", "misconception": "Placing Coulomb before Franklin"}, {"option_key": "C", "hint": "Millikan (1909) came after Thomson (1897), not before. Millikan measured the charge of the electron that Thomson had discovered.", "misconception": "Thinking Millikan''s experiment preceded Thomson''s discovery of the electron"}, {"option_key": "D", "hint": "This puts the most recent (Millikan, 1909) first and the earliest (Franklin, 1752) last — completely reversed chronology.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The electric field at a point is defined as:", "explanation": "Electric field E at a point is defined as the force F experienced by a unit positive test charge q₀ placed at that point: E = F/q₀. The test charge must be vanishingly small so it doesn''t disturb the source charge distribution. The field is a vector quantity with SI unit N/C or V/m.", "correct_answer": "B", "concept_tags": ["electric-field-definition", "test-charge", "vector"], "payload": {"question_id": "cuet-phy-elec-field-01", "subtopic": "Definition of electric field", "topic_name": "Electric Field and Field Lines", "bloom_level": "remember", "options": [{"key": "A", "text": "Force experienced by any charge at that point", "is_correct": false}, {"key": "B", "text": "Force per unit positive test charge at that point", "is_correct": true}, {"key": "C", "text": "Work done per unit charge", "is_correct": false}, {"key": "D", "text": "Charge per unit area", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The force depends on the magnitude of the test charge. The field is force per UNIT charge, making it independent of the test charge.", "misconception": "Confusing total force with field (force per unit charge)"}, {"option_key": "C", "hint": "Work done per unit charge is the definition of electric potential (V), not electric field (E).", "misconception": "Confusing electric field with electric potential"}, {"option_key": "D", "hint": "Charge per unit area is the definition of surface charge density (σ), not electric field.", "misconception": "Confusing electric field with charge density"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Electric field lines start from:", "explanation": "Electric field lines originate from positive charges and terminate on negative charges. They represent the direction of force that a positive test charge would experience. If there are no negative charges nearby, field lines extend to infinity.", "correct_answer": "A", "concept_tags": ["field-lines", "positive-charge", "negative-charge"], "payload": {"question_id": "cuet-phy-elec-field-02", "subtopic": "Properties of field lines", "topic_name": "Electric Field and Field Lines", "bloom_level": "remember", "options": [{"key": "A", "text": "Positive charges and end on negative charges", "is_correct": true}, {"key": "B", "text": "Negative charges and end on positive charges", "is_correct": false}, {"key": "C", "text": "Any charge and form closed loops", "is_correct": false}, {"key": "D", "text": "Regions of low field and end at regions of high field", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is the reverse of the convention. Field lines indicate the direction a positive test charge would move — away from positive, toward negative.", "misconception": "Reversing the direction convention for field lines"}, {"option_key": "C", "hint": "Electrostatic field lines never form closed loops — that''s a property of magnetic field lines. Electric field is conservative.", "misconception": "Confusing electric field lines with magnetic field lines"}, {"option_key": "D", "hint": "Field lines originate and terminate on charges, not on regions of different field strength.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The SI unit of electric field intensity is equivalent to:", "explanation": "Electric field E = F/q has SI unit N/C (newton per coulomb). Since work = force × distance, and potential V = W/q, we get V = Ed, so E = V/d, giving units V/m (volt per metre). Both N/C and V/m are equivalent and interchangeable.", "correct_answer": "C", "concept_tags": ["SI-units", "electric-field", "equivalence"], "payload": {"question_id": "cuet-phy-elec-field-03", "subtopic": "Units of electric field", "topic_name": "Electric Field and Field Lines", "bloom_level": "remember", "options": [{"key": "A", "text": "N/C only", "is_correct": false}, {"key": "B", "text": "V/m only", "is_correct": false}, {"key": "C", "text": "Both N/C and V/m", "is_correct": true}, {"key": "D", "text": "J/C", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "While N/C is correct, V/m is also a valid unit for electric field (E = −dV/dr). The question asks about equivalence.", "misconception": "Not knowing that N/C = V/m"}, {"option_key": "B", "hint": "V/m is correct but N/C is equally valid. E = F/q gives N/C directly.", "misconception": "Thinking only the potential-based unit is valid"}, {"option_key": "D", "hint": "J/C is the unit of electric potential (V), not electric field. E has an additional 1/m factor.", "misconception": "Confusing potential (J/C = V) with field (V/m)"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Two electric field lines can never cross each other because:", "explanation": "If two field lines crossed, there would be two different directions of electric field at the crossing point, which is impossible — the electric field at any point has a unique direction. This is because the field is a well-defined vector function of position.", "correct_answer": "D", "concept_tags": ["field-lines-properties", "uniqueness", "vector-field"], "payload": {"question_id": "cuet-phy-elec-field-04", "subtopic": "Properties of field lines", "topic_name": "Electric Field and Field Lines", "bloom_level": "understand", "options": [{"key": "A", "text": "Field lines are always straight", "is_correct": false}, {"key": "B", "text": "Field lines carry energy", "is_correct": false}, {"key": "C", "text": "Charges would cancel at the crossing point", "is_correct": false}, {"key": "D", "text": "The electric field at a point must have a unique direction", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Field lines are NOT always straight — they curve around charge distributions. This is not the reason they can''t cross.", "misconception": "Thinking field lines are always straight"}, {"option_key": "B", "hint": "Whether field lines carry energy is irrelevant to why they can''t cross. The reason is about direction uniqueness.", "misconception": null}, {"option_key": "C", "hint": "Field lines don''t represent charges — they represent the direction and strength of the field. There''s no charge at a crossing point.", "misconception": "Confusing field lines with charges"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The electric field due to a point charge q at distance r from it varies as:", "explanation": "From Coulomb''s law, E = kq/r² = q/(4πε₀r²). The field follows an inverse square law — it decreases as the square of the distance from the charge. At twice the distance, the field is one-fourth.", "correct_answer": "A", "concept_tags": ["inverse-square", "point-charge-field", "distance-dependence"], "payload": {"question_id": "cuet-phy-elec-field-05", "subtopic": "Field due to a point charge", "topic_name": "Electric Field and Field Lines", "bloom_level": "remember", "options": [{"key": "A", "text": "1/r²", "is_correct": true}, {"key": "B", "text": "1/r", "is_correct": false}, {"key": "C", "text": "1/r³", "is_correct": false}, {"key": "D", "text": "r²", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "1/r dependence applies to the electric field of an infinitely long line charge, not a point charge.", "misconception": "Confusing point charge field with line charge field"}, {"option_key": "C", "hint": "1/r³ dependence applies to the electric field of a dipole at large distances, not a single point charge.", "misconception": "Confusing point charge field with dipole field"}, {"option_key": "D", "hint": "r² would mean the field increases with distance, which contradicts the fact that the field weakens as you move away from a charge.", "misconception": "Inverting the relationship — confusing direct with inverse"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two point charges +q and −q are placed at equal distances from a point P. The electric field at P is:", "explanation": "This depends on the geometry. If P is on the perpendicular bisector of the line joining the charges: the field components along the bisector cancel, and the net field points from +q toward −q (parallel to the line joining the charges). If P is on the line joining them between the charges: both fields point toward −q and add up. In general, the field is NOT zero because the fields from opposite charges don''t cancel (they point in the same general direction at most points).", "correct_answer": "B", "concept_tags": ["superposition", "opposite-charges", "field-direction"], "payload": {"question_id": "cuet-phy-elec-field-06", "subtopic": "Superposition of electric fields", "topic_name": "Electric Field and Field Lines", "bloom_level": "understand", "options": [{"key": "A", "text": "Always zero", "is_correct": false}, {"key": "B", "text": "Non-zero and depends on the position of P", "is_correct": true}, {"key": "C", "text": "Always directed perpendicular to the line joining the charges", "is_correct": false}, {"key": "D", "text": "Always equal to 2kq/r²", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The fields from +q and −q at most points do NOT cancel because they generally point in similar directions (both have a component toward −q).", "misconception": "Assuming equal and opposite charges always produce zero field everywhere"}, {"option_key": "C", "hint": "This is true only on the perpendicular bisector. At other points (e.g., on the line joining the charges), the field is along that line.", "misconception": "Overgeneralising a result valid only on the bisector"}, {"option_key": "D", "hint": "The field magnitude varies with position and direction relative to the charges. 2kq/r² is not a universal expression.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The electric field at the midpoint of two equal positive charges +Q separated by distance 2d is:", "explanation": "At the midpoint, each charge is at distance d. The field from the left charge points rightward (away from +Q), and the field from the right charge points leftward (away from +Q). Both have equal magnitude kQ/d². Since they point in opposite directions, they cancel: E_net = 0.", "correct_answer": "C", "concept_tags": ["midpoint-field", "like-charges", "cancellation"], "payload": {"question_id": "cuet-phy-elec-field-07", "subtopic": "Field due to multiple charges", "topic_name": "Electric Field and Field Lines", "bloom_level": "apply", "options": [{"key": "A", "text": "2kQ/d², directed toward one charge", "is_correct": false}, {"key": "B", "text": "kQ/d², perpendicular to the line joining them", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": true}, {"key": "D", "text": "4kQ/d², directed along the line joining them", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The two fields are equal in magnitude but opposite in direction (both point away from their respective +Q source). They cancel perfectly at the midpoint.", "misconception": "Adding magnitudes instead of considering vector directions"}, {"option_key": "B", "hint": "There is no physical reason for a perpendicular field at the midpoint of two charges on a line. By symmetry, any net field must be along the line.", "misconception": "Assuming field direction without analysis"}, {"option_key": "D", "hint": "4kQ/d² would require the fields to add (same direction), but they point in opposite directions from the midpoint.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The number of electric field lines emerging from a charge of +1 C in vacuum is:", "explanation": "By Gauss''s law, the total electric flux from a charge q is Φ = q/ε₀. For q = 1 C: Φ = 1/(8.85 × 10⁻¹²) = 1.13 × 10¹¹ N·m²/C. If we associate one field line per unit flux, the number of lines is q/ε₀ ≈ 1.13 × 10¹¹. This is conventionally written as 1/ε₀.", "correct_answer": "D", "concept_tags": ["field-lines-number", "gauss-law", "flux"], "payload": {"question_id": "cuet-phy-elec-field-08", "subtopic": "Quantitative field line concept", "topic_name": "Electric Field and Field Lines", "bloom_level": "apply", "options": [{"key": "A", "text": "1", "is_correct": false}, {"key": "B", "text": "4π", "is_correct": false}, {"key": "C", "text": "9 × 10⁹", "is_correct": false}, {"key": "D", "text": "1/ε₀ ≈ 1.13 × 10¹¹", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "1 field line for 1 C of charge would be far too few. The number is proportional to q/ε₀, which is a very large number.", "misconception": "Thinking one line per coulomb"}, {"option_key": "B", "hint": "4π appears in the factor 4πε₀ in Coulomb''s law, but the number of field lines from 1 C is 1/ε₀, not 4π.", "misconception": "Confusing 4π factor with the field line count"}, {"option_key": "C", "hint": "9 × 10⁹ is the Coulomb constant k = 1/(4πε₀), not 1/ε₀. The number of lines is 1/ε₀ = 4πk ≈ 1.13 × 10¹¹.", "misconception": "Using k instead of 1/ε₀"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An electron is placed in a uniform electric field of 2 × 10⁴ N/C directed upward. The force on the electron is:", "explanation": "Force on charge q in field E: F = qE. For electron: F = eE = 1.6 × 10⁻¹⁹ × 2 × 10⁴ = 3.2 × 10⁻¹⁵ N. Since the electron is negative, the force is opposite to the field direction — i.e., downward. The force direction is opposite to E for negative charges.", "correct_answer": "A", "concept_tags": ["force-on-charge", "uniform-field", "electron"], "payload": {"question_id": "cuet-phy-elec-field-09", "subtopic": "Force on a charge in electric field", "topic_name": "Electric Field and Field Lines", "bloom_level": "apply", "options": [{"key": "A", "text": "3.2 × 10⁻¹⁵ N, directed downward", "is_correct": true}, {"key": "B", "text": "3.2 × 10⁻¹⁵ N, directed upward", "is_correct": false}, {"key": "C", "text": "1.6 × 10⁻¹⁵ N, directed downward", "is_correct": false}, {"key": "D", "text": "3.2 × 10⁻¹⁵ N, perpendicular to the field", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The magnitude is correct but the direction is wrong. Electrons (negative charge) experience force opposite to the electric field direction.", "misconception": "Forgetting that negative charges move opposite to the field"}, {"option_key": "C", "hint": "The direction is correct (downward) but the magnitude is halved. F = eE = 1.6×10⁻¹⁹ × 2×10⁴ = 3.2×10⁻¹⁵ N, not 1.6.", "misconception": "Arithmetic error in force calculation"}, {"option_key": "D", "hint": "The electric force on a charge always acts along the electric field (or opposite to it for negative charges), never perpendicular.", "misconception": "Confusing electric force with magnetic force (which is perpendicular)"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The electric field inside a uniformly charged thin spherical shell is:", "explanation": "By Gauss''s law, choosing a Gaussian surface inside the shell: the enclosed charge is zero (all charge is on the shell). Therefore, ∮E·dA = q_enc/ε₀ = 0, giving E = 0 everywhere inside. This is a fundamental result — a uniformly charged shell creates no field in its interior.", "correct_answer": "B", "concept_tags": ["spherical-shell", "gauss-law", "zero-field"], "payload": {"question_id": "cuet-phy-elec-field-10", "subtopic": "Field of symmetric charge distributions", "topic_name": "Electric Field and Field Lines", "bloom_level": "understand", "options": [{"key": "A", "text": "kQ/R², directed radially outward", "is_correct": false}, {"key": "B", "text": "Zero everywhere", "is_correct": true}, {"key": "C", "text": "kQ/r², where r is distance from centre", "is_correct": false}, {"key": "D", "text": "Proportional to r (increases linearly from centre)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "kQ/R² is the field at the surface of the shell (r = R), not inside it.", "misconception": "Using the surface field value for interior points"}, {"option_key": "C", "hint": "kQ/r² is the field outside the shell (r > R). Inside (r < R), the enclosed charge is zero.", "misconception": "Confusing the outside field formula with the interior"}, {"option_key": "D", "hint": "Linear increase with r describes the field inside a uniformly charged solid sphere, not a hollow shell.", "misconception": "Confusing solid sphere with hollow shell"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a region where the electric field is uniform, the field lines are:", "explanation": "In a uniform electric field, the magnitude and direction of E are the same everywhere. Therefore, field lines must be equidistant (same density = same magnitude) and parallel (same direction). They are straight lines with equal spacing.", "correct_answer": "D", "concept_tags": ["uniform-field", "field-lines", "parallel-lines"], "payload": {"question_id": "cuet-phy-elec-field-11", "subtopic": "Properties of field lines", "topic_name": "Electric Field and Field Lines", "bloom_level": "understand", "options": [{"key": "A", "text": "Converging toward a point", "is_correct": false}, {"key": "B", "text": "Diverging from a point", "is_correct": false}, {"key": "C", "text": "Curved lines of varying spacing", "is_correct": false}, {"key": "D", "text": "Parallel, equally spaced straight lines", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Converging lines indicate increasing field strength in that direction, which contradicts the definition of a uniform field.", "misconception": "Confusing uniform field with the field near a negative charge"}, {"option_key": "B", "hint": "Diverging lines indicate a positive point charge source. Uniform field doesn''t diverge.", "misconception": "Confusing uniform field with radial field"}, {"option_key": "C", "hint": "Curved lines with varying spacing represent a non-uniform field (like near a charge or dipole).", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The electric field on the axis of a uniformly charged disc of radius R and surface charge density σ, at a distance x from the centre (where x << R), is approximately:", "explanation": "The exact field on the axis of a charged disc is E = (σ/2ε₀)[1 − x/√(x² + R²)]. When x << R: √(x² + R²) ≈ R, so E ≈ (σ/2ε₀)[1 − x/R] ≈ σ/2ε₀ (since x/R → 0). This is the same as the field due to an infinite plane sheet of charge, which makes sense — close to the disc, it looks like an infinite plane.", "correct_answer": "C", "concept_tags": ["charged-disc", "infinite-plane-limit", "surface-charge"], "payload": {"question_id": "cuet-phy-elec-field-12", "subtopic": "Field of continuous distributions", "topic_name": "Electric Field and Field Lines", "bloom_level": "apply", "options": [{"key": "A", "text": "σ/ε₀", "is_correct": false}, {"key": "B", "text": "σx/(2ε₀R)", "is_correct": false}, {"key": "C", "text": "σ/(2ε₀)", "is_correct": true}, {"key": "D", "text": "Zero", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "σ/ε₀ is the field between two infinite parallel plates (complete enclosure), not on one side of a single disc.", "misconception": "Confusing single plane field with two-plate field"}, {"option_key": "B", "hint": "This expression goes to zero as x → 0, but the field near an infinite plane is constant (σ/2ε₀), not zero.", "misconception": null}, {"option_key": "D", "hint": "The field at any finite distance from a charged disc is non-zero. It approaches σ/2ε₀ as x → 0.", "misconception": "Thinking the field is zero on the surface of the disc"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A proton is released from rest in a uniform electric field of magnitude 8 × 10⁴ V/m. The acceleration of the proton is (mass of proton = 1.67 × 10⁻²⁷ kg):", "explanation": "Force on proton: F = eE = 1.6 × 10⁻¹⁹ × 8 × 10⁴ = 1.28 × 10⁻¹⁴ N. Acceleration: a = F/m = 1.28 × 10⁻¹⁴ / 1.67 × 10⁻²⁷ = 7.66 × 10¹² m/s². The proton accelerates in the direction of the field (since it''s positive).", "correct_answer": "B", "concept_tags": ["proton-acceleration", "uniform-field", "newton-second-law"], "payload": {"question_id": "cuet-phy-elec-field-13", "subtopic": "Motion of charges in electric fields", "topic_name": "Electric Field and Field Lines", "bloom_level": "apply", "options": [{"key": "A", "text": "7.66 × 10¹⁰ m/s²", "is_correct": false}, {"key": "B", "text": "7.66 × 10¹² m/s²", "is_correct": true}, {"key": "C", "text": "1.28 × 10⁻¹⁴ m/s²", "is_correct": false}, {"key": "D", "text": "7.66 × 10¹⁵ m/s²", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "10¹⁰ is two orders of magnitude too small. Check: 10⁻¹⁴/10⁻²⁷ = 10¹³, so the order should be ~10¹².", "misconception": "Exponent arithmetic error"}, {"option_key": "C", "hint": "1.28 × 10⁻¹⁴ N is the force, not the acceleration. You need to divide by mass.", "misconception": "Reporting force instead of acceleration"}, {"option_key": "D", "hint": "10¹⁵ is three orders too large — possibly from using electron mass instead of proton mass.", "misconception": "Using electron mass instead of proton mass"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The electric field at a point on the equatorial line of a short electric dipole at distance r (r >> 2a) from the centre is E₁. If the point is now moved to the same distance r on the axial line, the electric field E₂ is:", "explanation": "For a short dipole at large distance r: Equatorial field E₁ = kp/r³. Axial field E₂ = 2kp/r³. Therefore E₂ = 2E₁. The axial field is always twice the equatorial field at the same distance from a dipole.", "correct_answer": "C", "concept_tags": ["dipole-field", "axial-equatorial", "ratio"], "payload": {"question_id": "cuet-phy-elec-field-14", "subtopic": "Dipole field comparison", "topic_name": "Electric Field and Field Lines", "bloom_level": "apply", "options": [{"key": "A", "text": "E₁/2", "is_correct": false}, {"key": "B", "text": "E₁", "is_correct": false}, {"key": "C", "text": "2E₁", "is_correct": true}, {"key": "D", "text": "4E₁", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "E₁/2 reverses the ratio. The axial field is stronger than equatorial, not weaker.", "misconception": "Inverting the axial-to-equatorial ratio"}, {"option_key": "B", "hint": "Equal fields would mean the axial and equatorial expressions are the same, but E_axial has a factor of 2 that E_equatorial doesn''t.", "misconception": "Assuming the field is the same in all directions at a given r"}, {"option_key": "D", "hint": "A factor of 4 would apply if the distance were halved (since E ∝ 1/r³), not for a change from equatorial to axial at the same r.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An electric dipole is placed in a non-uniform electric field. The dipole will experience:", "explanation": "In a non-uniform field, the forces on the two charges of the dipole are unequal (since E differs at their positions). This produces both a net torque (trying to align the dipole with the field) AND a net translational force (since F₊ ≠ F₋). In contrast, a uniform field produces only torque (no net force). The dipole moves toward the region of stronger field.", "correct_answer": "A", "concept_tags": ["dipole-in-field", "non-uniform-field", "torque-and-force"], "payload": {"question_id": "cuet-phy-elec-field-15", "subtopic": "Dipole in external field", "topic_name": "Electric Field and Field Lines", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both a net force and a net torque", "is_correct": true}, {"key": "B", "text": "Only a net torque, no net force", "is_correct": false}, {"key": "C", "text": "Only a net force, no net torque", "is_correct": false}, {"key": "D", "text": "Neither net force nor net torque", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "''Only torque, no force'' is true for a UNIFORM field. In a non-uniform field, the unequal forces on the two charges create a net translational force as well.", "misconception": "Applying the uniform-field result to a non-uniform field"}, {"option_key": "C", "hint": "The torque is always present (unless the dipole is already aligned with the field). There''s no scenario where there''s force but no torque in a non-uniform field.", "misconception": null}, {"option_key": "D", "hint": "A dipole in any external field (uniform or not) experiences at least a torque (unless aligned). In non-uniform fields, it also has a net force.", "misconception": "Thinking a dipole doesn''t interact with external fields"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The electric field inside a uniformly charged solid non-conducting sphere of radius R and total charge Q, at a distance r from the centre (r < R), is:", "explanation": "Using Gauss''s law with a spherical Gaussian surface of radius r inside the sphere: q_enc = Q(r³/R³) (charge enclosed proportional to volume). By Gauss''s law: E × 4πr² = Q(r³/R³)/ε₀. Solving: E = Qr/(4πε₀R³) = kQr/R³. The field increases linearly from centre to surface.", "correct_answer": "D", "concept_tags": ["solid-sphere", "gauss-law", "linear-field"], "payload": {"question_id": "cuet-phy-elec-field-16", "subtopic": "Gauss''s law applications", "topic_name": "Electric Field and Field Lines", "bloom_level": "apply", "options": [{"key": "A", "text": "kQ/r²", "is_correct": false}, {"key": "B", "text": "kQ/R²", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": false}, {"key": "D", "text": "kQr/R³", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "kQ/r² is the field OUTSIDE the sphere (r > R). Inside, only the enclosed charge contributes, which is less than Q.", "misconception": "Using total charge Q instead of enclosed charge for interior points"}, {"option_key": "B", "hint": "kQ/R² is the field at the surface (r = R). Inside, the field varies linearly with r, it''s not constant.", "misconception": "Using surface value for all interior points"}, {"option_key": "C", "hint": "Zero field inside applies to a conducting sphere or a hollow shell, not a solid non-conducting sphere with uniform volume charge.", "misconception": "Confusing non-conducting solid sphere with conducting sphere or shell"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The torque experienced by an electric dipole of moment p placed in a uniform electric field E at angle θ to the field is maximum when θ equals:", "explanation": "Torque τ = pE sinθ. This is maximum when sinθ = 1, i.e., θ = 90°. When the dipole is perpendicular to the field, the torque is maximum (τ_max = pE). At θ = 0° (aligned) or θ = 180° (anti-aligned), the torque is zero.", "correct_answer": "B", "concept_tags": ["dipole-torque", "maximum-torque", "angle"], "payload": {"question_id": "cuet-phy-elec-field-17", "subtopic": "Dipole in uniform field", "topic_name": "Electric Field and Field Lines", "bloom_level": "apply", "options": [{"key": "A", "text": "0°", "is_correct": false}, {"key": "B", "text": "90°", "is_correct": true}, {"key": "C", "text": "180°", "is_correct": false}, {"key": "D", "text": "45°", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "At θ = 0°, the dipole is aligned with the field and sin0° = 0, so the torque is zero (stable equilibrium).", "misconception": "Confusing equilibrium position with maximum torque position"}, {"option_key": "C", "hint": "At θ = 180°, sin180° = 0, so the torque is again zero (unstable equilibrium). Maximum torque requires sinθ = 1.", "misconception": "Confusing unstable equilibrium with maximum torque"}, {"option_key": "D", "hint": "At 45°, sin45° = 1/√2, which gives τ = pE/√2 — this is about 71% of maximum, not the maximum itself.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The electric field due to an infinitely long straight wire with uniform linear charge density λ at perpendicular distance r from the wire is:", "explanation": "Using Gauss''s law with a cylindrical Gaussian surface of radius r and length l: E × 2πrl = λl/ε₀. Solving: E = λ/(2πε₀r). The field is directed radially outward (for positive λ) and falls off as 1/r — slower than the 1/r² of a point charge.", "correct_answer": "A", "concept_tags": ["infinite-wire", "gauss-law", "linear-charge-density"], "payload": {"question_id": "cuet-phy-elec-field-18", "subtopic": "Field of symmetric distributions", "topic_name": "Electric Field and Field Lines", "bloom_level": "apply", "options": [{"key": "A", "text": "λ/(2πε₀r)", "is_correct": true}, {"key": "B", "text": "λ/(4πε₀r²)", "is_correct": false}, {"key": "C", "text": "λ/(ε₀r)", "is_correct": false}, {"key": "D", "text": "λ/(4πε₀r)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This has 1/r² dependence (like a point charge) and uses 4πε₀ in the denominator. The wire field has 1/r dependence and 2πε₀.", "misconception": "Applying point charge formula to a line charge"}, {"option_key": "C", "hint": "λ/ε₀r is missing the factor of 2π from the cylindrical Gaussian surface area (2πrl).", "misconception": "Incorrect Gaussian surface area calculation"}, {"option_key": "D", "hint": "4πε₀r uses the wrong geometric factor. For cylindrical symmetry, the surface area gives 2πrl, leading to 2πε₀ in the denominator.", "misconception": "Using the spherical factor 4πε₀ for a cylindrical problem"}]}}]'::jsonb, 'deploy-2026-03-05-b03');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The electric field at a point on the surface of a charged conductor is perpendicular to the surface.\nReason (R): If there were a tangential component of the field, the free charges on the conductor surface would move, contradicting electrostatic equilibrium.", "explanation": "Both A and R are correct, and R is the correct explanation of A. In electrostatic equilibrium, charges on a conductor are stationary. If E had a tangential component at the surface, it would exert a force on the free charges, causing them to move — violating the assumption of static equilibrium. Therefore, E must be perpendicular to the surface.", "correct_answer": "A", "concept_tags": ["conductor-surface", "perpendicular-field", "equilibrium"], "payload": {"question_id": "cuet-phy-elec-field-19", "subtopic": "Conductors in electrostatic equilibrium", "topic_name": "Electric Field and Field Lines", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains A — the absence of tangential force (which would move charges) is exactly why the field must be perpendicular.", "misconception": "Not recognising the causal connection between charge motion and field direction"}, {"option_key": "C", "hint": "R is factually correct — free charges would indeed move if there were a tangential field component.", "misconception": null}, {"option_key": "D", "hint": "A is correct — electric field is always perpendicular to a conductor surface in electrostatic equilibrium.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): The density of electric field lines is proportional to the magnitude of the electric field at that point.\nReason (R): Electric field lines are drawn such that the number of lines per unit cross-sectional area is proportional to E.", "explanation": "Both A and R are correct, and R correctly explains A. By convention, field lines are drawn so that the number of lines crossing a unit area perpendicular to the lines equals the field magnitude. This is why regions of closely spaced lines have stronger fields, and widely spaced lines indicate weaker fields.", "correct_answer": "A", "concept_tags": ["field-line-density", "field-magnitude", "convention"], "payload": {"question_id": "cuet-phy-elec-field-20", "subtopic": "Field line interpretation", "topic_name": "Electric Field and Field Lines", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R is precisely the convention that makes A true — the density of field lines represents field strength because they are drawn that way. R explains A.", "misconception": "Not seeing that R is the definition that makes A true"}, {"option_key": "C", "hint": "R is correct — this is the standard convention for drawing field lines in physics.", "misconception": null}, {"option_key": "D", "hint": "A is correct — field line density does represent field magnitude. This is how field maps work.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The electric field between two large parallel plates carrying equal and opposite surface charge densities +σ and −σ is:", "explanation": "Each plate produces a field σ/(2ε₀). Between the plates, both fields point in the same direction (from + to − plate), so they add: E = σ/(2ε₀) + σ/(2ε₀) = σ/ε₀. Outside the plates, the fields cancel. This is the basis of a parallel plate capacitor.", "correct_answer": "C", "concept_tags": ["parallel-plates", "superposition", "uniform-field"], "payload": {"question_id": "cuet-phy-elec-field-21", "subtopic": "Field between parallel plates", "topic_name": "Electric Field and Field Lines", "bloom_level": "understand", "options": [{"key": "A", "text": "σ/(2ε₀)", "is_correct": false}, {"key": "B", "text": "2σ/ε₀", "is_correct": false}, {"key": "C", "text": "σ/ε₀", "is_correct": true}, {"key": "D", "text": "Zero", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "σ/(2ε₀) is the field due to a single infinite plate. Between two oppositely charged plates, both fields add up.", "misconception": "Considering only one plate instead of both"}, {"option_key": "B", "hint": "2σ/ε₀ would arise from incorrectly doubling the combined field. Each plate contributes σ/(2ε₀), and the total is σ/ε₀.", "misconception": "Double-counting the field contributions"}, {"option_key": "D", "hint": "Zero field exists outside the plates (fields cancel), not between them. Between the plates, the fields reinforce.", "misconception": "Confusing the region between the plates with the region outside"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A charge q is placed at the centre of a cube. The electric flux through one face of the cube is:", "explanation": "By Gauss''s law, total flux through the cube = q/ε₀. By symmetry, the cube has 6 identical faces, so flux through each face = q/(6ε₀). This is a standard application of Gauss''s law using symmetry arguments.", "correct_answer": "D", "concept_tags": ["gauss-law", "flux-through-face", "symmetry", "cube"], "payload": {"question_id": "cuet-phy-elec-field-22", "subtopic": "Electric flux and Gauss''s law", "topic_name": "Electric Field and Field Lines", "bloom_level": "apply", "options": [{"key": "A", "text": "q/ε₀", "is_correct": false}, {"key": "B", "text": "q/(2ε₀)", "is_correct": false}, {"key": "C", "text": "q/(4ε₀)", "is_correct": false}, {"key": "D", "text": "q/(6ε₀)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "q/ε₀ is the total flux through all 6 faces, not just one face.", "misconception": "Using total flux instead of dividing by the number of faces"}, {"option_key": "B", "hint": "Dividing by 2 suggests only 2 faces, but a cube has 6 symmetric faces.", "misconception": "Dividing by 2 instead of 6"}, {"option_key": "C", "hint": "Dividing by 4 suggests 4 faces. A cube has 6 faces, each receiving an equal share of flux.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Electric field lines are always perpendicular to equipotential surfaces.\nReason (R): No work is done in moving a charge along an equipotential surface.", "explanation": "Both A and R are correct, and R explains A. On an equipotential surface, V is constant, so dV = 0. Work done dW = q·dV = 0. Since W = F·ds·cosθ = qE·ds·cosθ = 0 and q ≠ 0, ds ≠ 0, E ≠ 0, we need cosθ = 0, meaning θ = 90°. Therefore E is perpendicular to the surface.", "correct_answer": "B", "concept_tags": ["equipotential", "perpendicularity", "work-done"], "payload": {"question_id": "cuet-phy-elec-field-27", "subtopic": "Equipotential surfaces", "topic_name": "Electric Field and Field Lines", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": true}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "R is correct — by definition, potential is constant on an equipotential surface, so work done in moving a charge along it is zero.", "misconception": "Thinking work is done along equipotential surfaces"}, {"option_key": "C", "hint": "A is correct — it is a standard result that E is perpendicular to equipotential surfaces. This follows directly from E = −∇V.", "misconception": null}, {"option_key": "D", "hint": "Read carefully — this option says the same as B. Both state R correctly explains A, which is true.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Electrostatic field lines do not form closed loops.\nReason (R): The electrostatic field is conservative in nature.", "explanation": "Both A and R are correct, and R correctly explains A. A conservative field has zero circulation: ∮E·dl = 0. If field lines formed closed loops, this integral would be non-zero (positive work done around the loop), contradicting the conservative nature. Hence, electrostatic field lines are open — they start on positive charges and end on negative charges.", "correct_answer": "D", "concept_tags": ["conservative-field", "closed-loops", "circulation"], "payload": {"question_id": "cuet-phy-elec-field-28", "subtopic": "Nature of electrostatic field", "topic_name": "Electric Field and Field Lines", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "B", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "C", "text": "A is incorrect but R is correct", "is_correct": false}, {"key": "D", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The conservative nature IS the reason field lines can''t form closed loops — zero circulation means no closed paths. R directly explains A.", "misconception": "Not seeing the connection between conservative fields and open field lines"}, {"option_key": "B", "hint": "R is correct — the electrostatic field is indeed conservative (curl E = 0).", "misconception": null}, {"option_key": "C", "hint": "A is correct — electrostatic field lines never form closed loops, unlike magnetic field lines.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the charge distribution in Column I with the distance dependence of its electric field in Column II:\n\nColumn I:\nP. Point charge\nQ. Infinite line charge\nR. Infinite plane sheet\nS. Electric dipole (far field)\n\nColumn II:\n1. E ∝ 1/r\n2. E ∝ 1/r²\n3. E ∝ 1/r³\n4. E is constant (independent of r)", "explanation": "Point charge: E = kq/r² → P-2. Infinite line charge: E = λ/(2πε₀r) → Q-1. Infinite plane: E = σ/(2ε₀) → R-4 (constant). Dipole far field: E ∝ 1/r³ → S-3.", "correct_answer": "B", "concept_tags": ["distance-dependence", "field-expressions", "charge-distributions"], "payload": {"question_id": "cuet-phy-elec-field-29", "subtopic": "Comparison of field expressions", "topic_name": "Electric Field and Field Lines", "bloom_level": "analyze", "options": [{"key": "A", "text": "P-2, Q-3, R-4, S-1", "is_correct": false}, {"key": "B", "text": "P-2, Q-1, R-4, S-3", "is_correct": true}, {"key": "C", "text": "P-1, Q-2, R-3, S-4", "is_correct": false}, {"key": "D", "text": "P-3, Q-1, R-4, S-2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This assigns 1/r³ to line charge and 1/r to dipole. Line charge has 1/r (slower decay), dipole has 1/r³ (faster decay).", "misconception": "Swapping line charge and dipole field dependences"}, {"option_key": "C", "hint": "This assigns 1/r to point charge, but E ∝ 1/r² for a point charge (inverse square law).", "misconception": "Confusing point charge field with line charge field"}, {"option_key": "D", "hint": "This assigns 1/r³ to point charge and 1/r² to dipole. The point charge has 1/r² and the dipole has 1/r³.", "misconception": "Swapping point charge and dipole field dependences"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the physical situation in Column I with the correct statement about electric field in Column II:\n\nColumn I:\nP. Inside a charged conducting sphere\nQ. Inside a uniformly charged non-conducting solid sphere\nR. Between parallel plates (+σ and −σ)\nS. Outside a spherical shell at distance r > R\n\nColumn II:\n1. E = kQ/r² (same as point charge)\n2. E = 0\n3. E = σ/ε₀ (uniform)\n4. E increases linearly with distance from centre", "explanation": "Inside a conducting sphere: E = 0 (P-2). Inside a non-conducting solid sphere: E = kQr/R³, linearly increasing (Q-4). Between parallel plates: E = σ/ε₀, uniform (R-3). Outside a shell: E = kQ/r², same as point charge (S-1).", "correct_answer": "C", "concept_tags": ["gauss-law-applications", "field-comparison", "conductor-vs-insulator"], "payload": {"question_id": "cuet-phy-elec-field-30", "subtopic": "Electric field in various geometries", "topic_name": "Electric Field and Field Lines", "bloom_level": "analyze", "options": [{"key": "A", "text": "P-2, Q-1, R-3, S-4", "is_correct": false}, {"key": "B", "text": "P-4, Q-2, R-3, S-1", "is_correct": false}, {"key": "C", "text": "P-2, Q-4, R-3, S-1", "is_correct": true}, {"key": "D", "text": "P-2, Q-3, R-4, S-1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This assigns kQ/r² to inside a solid sphere, but inside a solid sphere E increases linearly with r, not as 1/r².", "misconception": "Using the external field formula for interior points"}, {"option_key": "B", "hint": "This assigns linearly increasing field to inside a conductor. Inside a conductor, E = 0 always (charges reside on the surface).", "misconception": "Confusing conductor with non-conducting solid sphere"}, {"option_key": "D", "hint": "This swaps the field between parallel plates (σ/ε₀) with the solid sphere interior (linear). The plates give uniform field, the solid sphere gives linear.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Electric field lines always originate from positive charges and terminate on negative charges.", "explanation": "This statement is TRUE. By convention, electric field lines emerge from positive charges (sources) and end on negative charges (sinks). If no negative charge is present, lines extend to infinity. This is a fundamental property of electrostatic field lines.", "correct_answer": "A", "concept_tags": ["field-line-convention", "positive-negative-charges"], "payload": {"question_id": "cuet-phy-elec-field-31", "subtopic": "Properties of electric field lines", "topic_name": "Electric Field and Field Lines", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is a correct and fundamental property of electrostatic field lines — they originate from positive and terminate on negative charges.", "misconception": "Thinking field lines can originate from negative charges or form loops"}, {"option_key": "C", "hint": "This option is not applicable for true/false questions.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for true/false questions.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The total electric flux through a closed surface depends on the shape and size of the surface.", "explanation": "This statement is FALSE. By Gauss''s law, the total electric flux through any closed surface Φ = q_enc/ε₀, which depends ONLY on the net charge enclosed, not on the shape or size of the surface. A large sphere and a small cube enclosing the same charge will have the same total flux.", "correct_answer": "B", "concept_tags": ["gauss-law", "electric-flux", "closed-surface"], "payload": {"question_id": "cuet-phy-elec-field-32", "subtopic": "Gauss''s law fundamentals", "topic_name": "Electric Field and Field Lines", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Gauss''s law states Φ = q_enc/ε₀. The flux depends only on enclosed charge, not on the surface geometry.", "misconception": "Confusing flux density (which varies over a surface) with total flux (which depends only on enclosed charge)"}, {"option_key": "C", "hint": "This option is not applicable for true/false questions.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for true/false questions.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The electric field at a point due to a positive charge is directed away from the charge.", "explanation": "This statement is TRUE. A positive charge repels a positive test charge. Since the electric field direction is defined as the direction of force on a positive test charge, the field points radially away from a positive source charge.", "correct_answer": "A", "concept_tags": ["field-direction", "positive-charge", "convention"], "payload": {"question_id": "cuet-phy-elec-field-33", "subtopic": "Direction of electric field", "topic_name": "Electric Field and Field Lines", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The electric field from a positive charge points outward (away). For a negative charge, it points inward (toward the charge).", "misconception": "Confusing the field direction of positive and negative charges"}, {"option_key": "C", "hint": "This option is not applicable for true/false questions.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for true/false questions.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "In a region where the electric field is zero, the electric potential must also be zero.", "explanation": "This statement is FALSE. E = 0 means there is no potential gradient (dV/dr = 0), so the potential is constant — but that constant need not be zero. Example: inside a charged conducting sphere, E = 0 but V = kQ/R (a non-zero constant).", "correct_answer": "B", "concept_tags": ["zero-field", "non-zero-potential", "conductor-interior"], "payload": {"question_id": "cuet-phy-elec-field-34", "subtopic": "Relation between E and V", "topic_name": "Electric Field and Field Lines", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Zero field means the potential is constant, not necessarily zero. Inside a charged conducting shell, E = 0 but V = kQ/R ≠ 0.", "misconception": "Confusing zero field (constant potential) with zero potential"}, {"option_key": "C", "hint": "This option is not applicable for true/false questions.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for true/false questions.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "easy", "question_text": "The electric flux through a closed surface enclosing a charge of 5 μC is ______ N·m²/C. (Given: ε₀ = 8.85 × 10⁻¹² C²/N·m²)", "explanation": "By Gauss''s law, Φ = q/ε₀ = 5 × 10⁻⁶ / 8.85 × 10⁻¹² = 5.65 × 10⁵ N·m²/C. This is a direct application of Gauss''s law — the flux depends only on the enclosed charge.", "correct_answer": "C", "concept_tags": ["gauss-law", "electric-flux", "calculation"], "payload": {"question_id": "cuet-phy-elec-field-35", "subtopic": "Electric flux calculation", "topic_name": "Electric Field and Field Lines", "bloom_level": "apply", "options": [{"key": "A", "text": "5.65 × 10³", "is_correct": false}, {"key": "B", "text": "5.65 × 10⁷", "is_correct": false}, {"key": "C", "text": "5.65 × 10⁵", "is_correct": true}, {"key": "D", "text": "5.65 × 10⁻⁵", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "10³ would result from dividing the exponents incorrectly. 10⁻⁶/10⁻¹² = 10⁶, giving ~5.65 × 10⁵.", "misconception": "Exponent arithmetic error"}, {"option_key": "B", "hint": "10⁷ is two orders too high. Check: 5/8.85 ≈ 0.565, and 10⁻⁶/10⁻¹² = 10⁶, so the answer is ~5.65 × 10⁵.", "misconception": null}, {"option_key": "D", "hint": "A negative exponent would mean extremely small flux, which is unreasonable for a microcoulomb charge.", "misconception": "Sign error in the exponent calculation"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "An electric dipole of moment 4 × 10⁻⁹ C·m is placed in a uniform electric field of 5 × 10⁵ N/C at 30° to the field. The torque on the dipole is ______ N·m.", "explanation": "Torque τ = pE sinθ = 4 × 10⁻⁹ × 5 × 10⁵ × sin30° = 4 × 10⁻⁹ × 5 × 10⁵ × 0.5 = 10⁻³ N·m = 1 × 10⁻³ N·m.", "correct_answer": "D", "concept_tags": ["dipole-torque", "uniform-field", "calculation"], "payload": {"question_id": "cuet-phy-elec-field-36", "subtopic": "Torque on a dipole", "topic_name": "Electric Field and Field Lines", "bloom_level": "apply", "options": [{"key": "A", "text": "2 × 10⁻³", "is_correct": false}, {"key": "B", "text": "4 × 10⁻³", "is_correct": false}, {"key": "C", "text": "1 × 10⁻⁴", "is_correct": false}, {"key": "D", "text": "1 × 10⁻³", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "2 × 10⁻³ would result from using sin60° (= √3/2 ≈ 0.866) instead of sin30° (= 0.5), or from forgetting the sin factor.", "misconception": "Using the wrong angle or cosine instead of sine"}, {"option_key": "B", "hint": "4 × 10⁻³ results from omitting the sinθ factor entirely (τ = pE without sin30°).", "misconception": "Forgetting the sine factor in the torque formula"}, {"option_key": "C", "hint": "10⁻⁴ is one order too small, likely from an exponent error: 10⁻⁹ × 10⁵ = 10⁻⁴ before the factor of 4×5×0.5 = 10.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "What is the charge on the oil droplet? (Take g = 10 m/s²)", "explanation": "For the droplet to be stationary, electric force must balance gravity: qE = mg. The electric field E = V/d = 200/0.05 = 4000 V/m. So q = mg/E = 3.2 × 10⁻¹⁵ × 10 / 4000 = 3.2 × 10⁻¹⁴/4000 = 8 × 10⁻¹⁸ C. This is exactly 50 electron charges (50 × 1.6 × 10⁻¹⁹), confirming charge quantisation.", "correct_answer": "A", "concept_tags": ["millikan-experiment", "balanced-droplet", "uniform-field"], "payload": {"question_id": "cuet-phy-elec-field-37", "subtopic": "Charge in uniform field — Millikan-type", "topic_name": "Electric Field and Field Lines", "bloom_level": "apply", "options": [{"key": "A", "text": "8 × 10⁻¹⁸ C", "is_correct": true}, {"key": "B", "text": "1.6 × 10⁻¹⁹ C", "is_correct": false}, {"key": "C", "text": "3.2 × 10⁻¹⁷ C", "is_correct": false}, {"key": "D", "text": "4 × 10⁻¹⁵ C", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "1.6 × 10⁻¹⁹ C is a single electron charge. The calculation gives q = mg/E = 8 × 10⁻¹⁸ C, which is 50e, not 1e.", "misconception": "Guessing the fundamental charge without calculating"}, {"option_key": "C", "hint": "3.2 × 10⁻¹⁷ is too large by a factor of 4, possibly from using d = 5 cm as 0.5 m instead of 0.05 m.", "misconception": "Unit conversion error for plate separation"}, {"option_key": "D", "hint": "4 × 10⁻¹⁵ would result from using E = V (200) instead of E = V/d (4000).", "misconception": "Using voltage directly instead of E = V/d"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "What can the team conclude about the electric field inside the cavity?", "explanation": "By superposition, E_inside cavity = E_full sphere − E_small sphere. For the full sphere at position r from its centre: E₁ = ρr/(3ε₀). For the negative sphere centred at distance d: E₂ = −ρr''/(3ε₀) where r'' is measured from the cavity centre. The net field: E = ρ(r − r'')/(3ε₀) = ρd/(3ε₀), where d is the vector from sphere centre to cavity centre. This is uniform inside the cavity — constant magnitude and direction.", "correct_answer": "B", "concept_tags": ["cavity-field", "superposition", "uniform-field-inside-cavity"], "payload": {"question_id": "cuet-phy-elec-field-38", "subtopic": "Advanced Gauss''s law application", "topic_name": "Electric Field and Field Lines", "bloom_level": "analyze", "options": [{"key": "A", "text": "The field is zero everywhere inside the cavity", "is_correct": false}, {"key": "B", "text": "The field is uniform (constant magnitude and direction) inside the cavity", "is_correct": true}, {"key": "C", "text": "The field increases linearly from the cavity centre", "is_correct": false}, {"key": "D", "text": "The field is radially symmetric about the cavity centre", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Zero field inside a cavity occurs only when the cavity is at the centre of the sphere (d = 0). For an off-centre cavity, the field is non-zero and uniform.", "misconception": "Assuming zero field inside any cavity regardless of its position"}, {"option_key": "C", "hint": "Linear increase with distance describes the field inside a uniformly charged solid sphere, not inside a cavity within such a sphere.", "misconception": "Confusing the cavity field with the solid sphere field"}, {"option_key": "D", "hint": "The cavity breaks the spherical symmetry. The resulting field is uniform (same everywhere in the cavity), not radially symmetric about the cavity centre.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following steps in the correct order for applying Gauss''s law to find the electric field due to a uniformly charged infinite plane sheet:", "explanation": "Step 1: Choose the appropriate Gaussian surface (cylinder). Step 2: State Gauss''s law. Step 3: Evaluate the surface integral using symmetry. Step 4: Find the enclosed charge. Step 5: Solve for E. This systematic approach works for all Gauss''s law problems.", "correct_answer": "D", "concept_tags": ["gauss-law-method", "infinite-plane", "systematic-approach"], "payload": {"question_id": "cuet-phy-elec-field-39", "subtopic": "Gauss''s law application procedure", "topic_name": "Electric Field and Field Lines", "bloom_level": "apply", "options": [{"key": "A", "text": "P → R → Q → S → T", "is_correct": false}, {"key": "B", "text": "Q → P → S → R → T", "is_correct": false}, {"key": "C", "text": "P → Q → S → R → T", "is_correct": false}, {"key": "D", "text": "P → Q → R → S → T", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Evaluating the surface integral (R) before writing Gauss''s law (Q) is out of order. You must state the law before applying it.", "misconception": "Skipping the formal statement of the law"}, {"option_key": "B", "hint": "Writing Gauss''s law before choosing the Gaussian surface doesn''t make physical sense — you need to define the surface first.", "misconception": "Not recognising that the surface must be chosen first"}, {"option_key": "C", "hint": "This puts enclosed charge (S) before evaluating the surface integral (R). You need to simplify the left side before computing the right side to solve for E.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "hard", "question_text": "Arrange the following charge distributions in order of increasing rate at which their electric field decreases with distance r (from slowest decrease to fastest decrease):", "explanation": "Slowest decrease: infinite plane (E = constant, no decrease at all). Then line charge (1/r). Then point charge (1/r²). Fastest decrease: dipole (1/r³). The rate of decrease correlates with the dimensionality: 2D sheet → 1D line → 0D point → dipole (which partially cancels).", "correct_answer": "A", "concept_tags": ["field-decrease-rate", "dimension-dependence", "ordering"], "payload": {"question_id": "cuet-phy-elec-field-40", "subtopic": "Comparison of field behaviours", "topic_name": "Electric Field and Field Lines", "bloom_level": "analyze", "options": [{"key": "A", "text": "P → Q → R → S", "is_correct": true}, {"key": "B", "text": "S → R → Q → P", "is_correct": false}, {"key": "C", "text": "P → R → Q → S", "is_correct": false}, {"key": "D", "text": "Q → P → R → S", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is the reverse order (fastest to slowest). The question asks for slowest decrease to fastest decrease.", "misconception": "Reversing the order asked for"}, {"option_key": "C", "hint": "This places point charge (1/r²) before line charge (1/r). But 1/r decreases slower than 1/r², so line charge should come before point charge.", "misconception": "Confusing which power law decreases faster"}, {"option_key": "D", "hint": "This places line charge before plane sheet. The plane sheet has constant E (no decrease at all), so it must come first.", "misconception": "Forgetting that the infinite plane field is constant"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The SI unit of electric dipole moment is:", "explanation": "Dipole moment p = qd, where q is in coulombs and d is in metres. So the SI unit is C·m (coulomb-metre). In CGS, the unit is debye (1 D = 3.33 × 10⁻³⁰ C·m), but the SI unit remains C·m.", "correct_answer": "A", "concept_tags": ["dipole-moment", "SI-units"], "payload": {"question_id": "cuet-phy-elec-dipole-01", "subtopic": "Dipole moment definition", "topic_name": "Electric Dipole", "bloom_level": "remember", "options": [{"key": "A", "text": "C·m (coulomb-metre)", "is_correct": true}, {"key": "B", "text": "C/m (coulomb per metre)", "is_correct": false}, {"key": "C", "text": "N·m (newton-metre)", "is_correct": false}, {"key": "D", "text": "C·m² (coulomb-metre squared)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "C/m would imply charge divided by distance. Dipole moment is charge multiplied by distance (p = qd).", "misconception": "Confusing multiplication with division in p = qd"}, {"option_key": "C", "hint": "N·m is the unit of torque. While torque on a dipole is τ = pE sinθ, the dipole moment itself has units of charge × distance.", "misconception": "Confusing dipole moment with torque"}, {"option_key": "D", "hint": "C·m² would require charge × distance², but p = q × d, not q × d².", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The direction of the electric dipole moment vector is:", "explanation": "By convention, the electric dipole moment vector p points from the negative charge to the positive charge. This convention is chosen so that p points in the direction of the electric field inside the dipole (from − to +), which is opposite to the external field direction.", "correct_answer": "B", "concept_tags": ["dipole-direction", "convention", "vector"], "payload": {"question_id": "cuet-phy-elec-dipole-02", "subtopic": "Dipole moment direction", "topic_name": "Electric Dipole", "bloom_level": "remember", "options": [{"key": "A", "text": "From positive to negative charge", "is_correct": false}, {"key": "B", "text": "From negative to positive charge", "is_correct": true}, {"key": "C", "text": "Perpendicular to the line joining the charges", "is_correct": false}, {"key": "D", "text": "Along the external electric field always", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is the direction of the electric field between the two charges of the dipole, not the dipole moment vector. The convention for p is opposite.", "misconception": "Confusing field direction with dipole moment direction"}, {"option_key": "C", "hint": "The dipole moment is along the line joining the charges, not perpendicular to it.", "misconception": null}, {"option_key": "D", "hint": "The dipole moment is a property of the dipole itself. It can be at any angle to the external field.", "misconception": "Confusing dipole moment with induced alignment"}]}}]'::jsonb, 'deploy-2026-03-05-b03');

COMMIT;
